'use client';

import { forwardRef, useImperativeHandle, useState } from 'react';

export interface TagsTabHandle {
  openCreate: () => void;
}
import {
  Button,
  Card,
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  EmptyState,
  Input,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@intelliflow/ui';
import {
  ACCOUNT_TAG_COLOR_TOKENS,
  type AccountTagColorToken,
  type CreateAccountTagInput,
  type UpdateAccountTagInput,
} from '@intelliflow/validators';

export interface TagRow {
  id: string;
  name: string;
  colorToken: AccountTagColorToken;
  description: string | null;
  sortOrder: number;
  isActive: boolean;
}

export interface TagsTabProps {
  readonly tags: TagRow[];
  readonly onCreate: (input: CreateAccountTagInput) => void | Promise<void>;
  readonly onUpdate: (input: UpdateAccountTagInput) => void | Promise<void>;
  readonly onDelete: (id: string) => void | Promise<void>;
  readonly isBusy?: boolean;
}

interface DialogState {
  open: boolean;
  editing?: TagRow;
  name: string;
  colorToken: AccountTagColorToken;
  description: string;
}

const EMPTY: DialogState = { open: false, name: '', colorToken: 'slate', description: '' };

export const TagsTab = forwardRef<TagsTabHandle, TagsTabProps>(function TagsTab(
  { tags, onCreate, onUpdate, onDelete, isBusy = false },
  ref
) {
  const [dialog, setDialog] = useState<DialogState>(EMPTY);

  const openCreate = () => setDialog({ ...EMPTY, open: true });
  useImperativeHandle(ref, () => ({ openCreate }));
  const openEdit = (tag: TagRow) =>
    setDialog({
      open: true,
      editing: tag,
      name: tag.name,
      colorToken: tag.colorToken,
      description: tag.description ?? '',
    });
  const close = () => setDialog(EMPTY);

  const submit = async () => {
    const name = dialog.name.trim();
    if (!name) return;
    const description = dialog.description.trim() || undefined;
    if (dialog.editing) {
      await onUpdate({ id: dialog.editing.id, name, colorToken: dialog.colorToken, description });
    } else {
      await onCreate({ name, colorToken: dialog.colorToken, description });
    }
    close();
  };

  return (
    <div className="space-y-3">
      {tags.length === 0 ? (
        <EmptyState
          entity="pinned"
          size="sm"
          title="No tags yet"
          description="Add the first account tag."
          action={{ label: 'Add Tag', icon: 'add', onClick: openCreate }}
        />
      ) : (
        <Card className="divide-y divide-border">
          {tags.map((tag) => (
            <div
              key={tag.id}
              className="flex items-center gap-3 px-4 py-3"
              data-testid={`tag-row-${tag.id}`}
            >
              <span
                className={`inline-block w-3 h-3 rounded-full bg-${tag.colorToken}-500`}
                aria-hidden
              />
              <div className="flex-1 min-w-0">
                <div className="text-sm font-medium text-foreground truncate">{tag.name}</div>
                {tag.description && (
                  <div className="text-xs text-muted-foreground truncate">{tag.description}</div>
                )}
              </div>
              <Button size="sm" variant="outline" onClick={() => openEdit(tag)} disabled={isBusy}>
                Edit
              </Button>
              <Button
                size="sm"
                variant="outline"
                onClick={() => onDelete(tag.id)}
                disabled={isBusy}
              >
                Delete
              </Button>
            </div>
          ))}
        </Card>
      )}

      <Dialog open={dialog.open} onOpenChange={(o) => (o ? null : close())}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{dialog.editing ? 'Edit tag' : 'Add tag'}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <div>
              <label htmlFor="tag-name" className="text-sm font-medium">
                Name
              </label>
              <Input
                id="tag-name"
                value={dialog.name}
                onChange={(e) => setDialog((d) => ({ ...d, name: e.target.value }))}
                placeholder="e.g. Strategic"
              />
            </div>
            <div>
              <label htmlFor="tag-color" className="text-sm font-medium">
                Color
              </label>
              <Select
                value={dialog.colorToken}
                onValueChange={(v) =>
                  setDialog((d) => ({ ...d, colorToken: v as AccountTagColorToken }))
                }
              >
                <SelectTrigger id="tag-color">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {ACCOUNT_TAG_COLOR_TOKENS.map((c) => (
                    <SelectItem key={c} value={c}>
                      {c}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <label htmlFor="tag-desc" className="text-sm font-medium">
                Description (optional)
              </label>
              <Input
                id="tag-desc"
                value={dialog.description}
                onChange={(e) => setDialog((d) => ({ ...d, description: e.target.value }))}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={close}>
              Cancel
            </Button>
            <Button onClick={submit} disabled={dialog.name.trim().length === 0}>
              {dialog.editing ? 'Save' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

/**
 * Agent Detail Page
 *
 * Shows a single agent's info, status, and full conversation transcript.
 * Route: /agent-approvals/logs/:id (id = agentId e.g. "ai-insights-v1")
 */

import { use, useState } from 'react';
import Link from 'next/link';
import { Card, CardContent, Skeleton, cn } from '@intelliflow/ui';
import { PageHeader } from '@/components/shared';
import { useRequireAuth } from '@/lib/auth/AuthContext';
import { useActiveAgentsDashboard } from '@/lib/active-agents/hooks';
import { useAgentLogs } from '@/lib/ai-monitoring/hooks';
import {
  getAgentTypeLabel,
  getAgentTypeIcon,
  getStatusBadgeClass,
  getStatusDotClass,
  formatLastActive,
} from '@/lib/active-agents/agent-utils';
import type { AgentLogMessage, AgentLogToolCall } from '@/lib/ai-monitoring/types';

// ---------------------------------------------------------------------------
// Utilities
// ---------------------------------------------------------------------------

function formatTimestamp(iso: string, timezone: string = 'Europe/London'): string {
  return new Date(iso).toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    timeZone: timezone,
  });
}

// ---------------------------------------------------------------------------
// Message List
// ---------------------------------------------------------------------------

function MessageList({ messages }: Readonly<{ messages: AgentLogMessage[] }>) {
  if (messages.length === 0) {
    return (
      <div className="px-4 py-6 text-center text-sm text-muted-foreground italic">
        No messages recorded yet. Messages will appear here when this agent processes jobs.
      </div>
    );
  }

  return (
    <div className="divide-y">
      {messages.map((msg, idx) => {
        const isError = msg.content.startsWith('Failed');
        return (
          <div
            key={`${msg.timestamp}-${idx}`}
            className={cn(
              'flex items-start gap-3 px-4 py-3',
              isError && 'bg-red-50/50 dark:bg-red-950/10'
            )}
          >
            <span
              className={cn(
                'mt-0.5 material-symbols-outlined text-base',
                isError
                  ? 'text-red-500'
                  : msg.content.startsWith('Completed')
                    ? 'text-green-500'
                    : 'text-blue-500'
              )}
            >
              {isError ? 'error' : msg.content.startsWith('Completed') ? 'check_circle' : 'play_circle'}
            </span>
            <div className="flex-1 min-w-0">
              <p className="text-sm whitespace-pre-wrap break-words">{msg.content}</p>
              <p className="text-xs text-muted-foreground mt-0.5">
                {formatTimestamp(msg.timestamp)}
              </p>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Tool Call List
// ---------------------------------------------------------------------------

const TOOL_STATUS_COLORS: Record<string, string> = {
  SUCCESS: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400',
  FAILED: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400',
  PENDING: 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-400',
  RUNNING: 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400',
};

function ToolCallList({ toolCalls }: Readonly<{ toolCalls: AgentLogToolCall[] }>) {
  const [expandedIdx, setExpandedIdx] = useState<number | null>(null);

  if (toolCalls.length === 0) return null;

  return (
    <Card>
      <CardContent className="p-0">
        <div className="px-4 py-3 border-b">
          <h3 className="text-sm font-semibold">Tool Calls</h3>
        </div>
        <div className="divide-y">
          {toolCalls.map((tc, idx) => {
            const isExpanded = expandedIdx === idx;
            return (
              <div key={`${tc.name}-${tc.timestamp}`}>
                <button
                  type="button"
                  className="flex w-full items-center gap-2 px-4 py-2.5 text-left hover:bg-muted/50"
                  onClick={() => setExpandedIdx(isExpanded ? null : idx)}
                >
                  <span className="text-sm font-medium">{tc.name}</span>
                  <span
                    className={cn(
                      'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium',
                      TOOL_STATUS_COLORS[tc.status] ?? 'bg-slate-100 text-slate-600'
                    )}
                  >
                    {tc.status}
                  </span>
                  <span className="ml-auto text-xs text-muted-foreground">
                    {formatTimestamp(tc.timestamp)}
                  </span>
                </button>
                {isExpanded && (
                  <div className="px-6 pb-3 space-y-2">
                    <div>
                      <p className="text-xs font-medium text-muted-foreground mb-1">Input</p>
                      <pre className="text-xs bg-muted/50 rounded p-2 overflow-auto max-h-48">
                        {JSON.stringify(tc.input, null, 2)}
                      </pre>
                    </div>
                    <div>
                      <p className="text-xs font-medium text-muted-foreground mb-1">Output</p>
                      <pre className="text-xs bg-muted/50 rounded p-2 overflow-auto max-h-48">
                        {JSON.stringify(tc.output, null, 2)}
                      </pre>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </CardContent>
    </Card>
  );
}

// ---------------------------------------------------------------------------
// Detail Content
// ---------------------------------------------------------------------------

function AgentDetailContent({ agentId }: Readonly<{ agentId: string }>) {
  const { isLoading: authLoading } = useRequireAuth();
  const { agents, isLoading: agentsLoading } = useActiveAgentsDashboard();
  const { logs, isLoading: logsLoading, refetch } = useAgentLogs({
    agentId,
    limit: 50,
    sort: 'newest',
  });

  const isLoading = authLoading || agentsLoading || logsLoading;

  // Find agent metadata from the active agents list
  const agent = agents.find((a) => a.agentId === agentId);
  const agentType = agent?.type ?? agentId.replace(/^ai-/, '').replace(/-v\d+$/, '');
  const label = getAgentTypeLabel(agentType);

  // Merge all messages across conversation logs (usually 1 conversation per agent)
  const allMessages = logs.flatMap((l) => l.messages);
  const allToolCalls = logs.flatMap((l) => l.toolCalls);

  const breadcrumbs = [
    { label: 'AI & Agents', href: '/agent-approvals' },
    { label: 'Active Agents', href: '/agent-approvals/agents' },
    { label },
  ];

  if (isLoading) {
    return (
      <div className="flex flex-col gap-6">
        <Skeleton className="h-8 w-64" />
        <Skeleton className="h-32 w-full rounded-lg" />
        <Skeleton className="h-64 w-full rounded-lg" />
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        breadcrumbs={breadcrumbs}
        title={label}
        description={`Agent logs and activity for ${agentId}`}
        actions={[
          {
            label: 'Refresh',
            icon: 'refresh',
            variant: 'secondary',
            onClick: refetch,
          },
        ]}
      />

      {/* Agent Info Card */}
      <Card>
        <CardContent className="p-5">
          <div className="flex items-start gap-4">
            <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-xl bg-primary/10 text-primary">
              <span className="material-symbols-outlined text-xl">
                {getAgentTypeIcon(agentType)}
              </span>
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-3 flex-wrap">
                <h2 className="text-lg font-semibold">{label}</h2>
                {agent && (
                  <span
                    className={cn(
                      'inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5 text-xs font-medium',
                      getStatusBadgeClass(agent.status)
                    )}
                  >
                    <span className={cn('h-1.5 w-1.5 rounded-full', getStatusDotClass(agent.status))} />
                    {agent.status.charAt(0).toUpperCase() + agent.status.slice(1)}
                  </span>
                )}
              </div>
              <div className="flex items-center gap-4 mt-2 text-sm text-muted-foreground flex-wrap">
                <span className="flex items-center gap-1">
                  <span className="material-symbols-outlined text-sm">badge</span>
                  {agentId}
                </span>
                {agent && (
                  <>
                    <span className="flex items-center gap-1">
                      <span className="material-symbols-outlined text-sm">memory</span>
                      {agent.model}
                    </span>
                    <span className="flex items-center gap-1">
                      <span className="material-symbols-outlined text-sm">schedule</span>
                      {formatLastActive(agent.lastActive)}
                    </span>
                  </>
                )}
              </div>
              {agent?.currentTask && (
                <p className="mt-2 text-sm">
                  <span className="text-muted-foreground">Current task: </span>
                  {agent.currentTask}
                </p>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Activity Log */}
      <Card>
        <CardContent className="p-0">
          <div className="flex items-center justify-between px-4 py-3 border-b">
            <h3 className="text-sm font-semibold">Activity Log</h3>
            <span className="text-xs text-muted-foreground">
              {allMessages.length} {allMessages.length === 1 ? 'entry' : 'entries'}
            </span>
          </div>
          <MessageList messages={allMessages} />
        </CardContent>
      </Card>

      {/* Tool Calls (if any) */}
      <ToolCallList toolCalls={allToolCalls} />

      {/* Back link */}
      <div>
        <Link
          href="/agent-approvals/agents"
          className="text-sm text-primary hover:underline inline-flex items-center gap-1"
        >
          <span className="material-symbols-outlined text-sm">arrow_back</span>
          Back to Active Agents
        </Link>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Page
// ---------------------------------------------------------------------------

export default function AgentLogsDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = use(params);

  return <AgentDetailContent agentId={id} />;
}

'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Card, EmptyState } from '@intelliflow/ui';
import { trpc } from '@/lib/trpc';
import { useAuth } from '@/lib/auth/AuthContext';
import { downloadCSV } from '@/lib/export/csv';
import { useAnalyticsDateRange, type PeriodKey } from '@/hooks/useAnalyticsDateRange';
import { refreshAnalyticsCache } from '@/app/analytics/actions';

export default function AnalyticsPage() {
  const [selectedPeriod, setSelectedPeriod] = useState<PeriodKey>('30d');
  const [exportMenuOpen, setExportMenuOpen] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);
  const { isAuthenticated, isLoading: authLoading, user } = useAuth();
  const dateRange = useAnalyticsDateRange(selectedPeriod);
  const enabled = isAuthenticated && !authLoading;

  // --- tRPC queries ---
  const { data: overview, isLoading: overviewLoading } = trpc.analytics.getOverview.useQuery(
    { startDate: dateRange.startDate, endDate: dateRange.endDate },
    { enabled }
  );

  const { data: funnel, isLoading: funnelLoading } = trpc.analytics.getConversionFunnel.useQuery(
    { startDate: dateRange.startDate, endDate: dateRange.endDate, includeLeads: true },
    { enabled }
  );

  const { data: timeSeries, isLoading: timeSeriesLoading } =
    trpc.analytics.getTimeSeriesData.useQuery(
      {
        metric: 'revenue',
        startDate: dateRange.startDate,
        endDate: dateRange.endDate,
        granularity: selectedPeriod === '7d' ? 'day' : 'month',
      },
      { enabled }
    );

  const { data: leadStats } = trpc.analytics.leadStats.useQuery(undefined, { enabled });

  // Close export menu when clicking outside
  useEffect(() => {
    function handleClickOutside(event: Readonly<MouseEvent>) {
      if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
        setExportMenuOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const utils = trpc.useUtils();

  const handleServerExport = useCallback(
    async (reportType: 'overview' | 'funnel' | 'sales') => {
      setExportMenuOpen(false);
      try {
        const result = await utils.analytics.exportReport.fetch({
          format: 'csv',
          reportType,
          startDate: dateRange.startDate,
          endDate: dateRange.endDate,
        });
        if (result && typeof result.data === 'string') {
          downloadCSV(result.data, result.filename);
        }
      } catch {
        // Fallback: if server export not available, silently fail
      }
    },
    [dateRange, utils]
  );

  const handleRefreshAnalytics = useCallback(() => {
    if (user?.id) refreshAnalyticsCache(user.id).catch(() => {});
  }, [user]);

  const isLoading = overviewLoading || authLoading;

  return (
    <>
      {/* Breadcrumb */}
      <nav className="flex items-center gap-2 text-sm text-muted-foreground mb-4">
        <Link href="/dashboard" className="hover:text-primary">
          Dashboard
        </Link>
        <span>/</span>
        <span className="text-foreground font-medium">Analytics</span>
      </nav>

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 mb-6">
        <div className="flex flex-col gap-1">
          <h1 className="text-3xl md:text-4xl font-black text-foreground tracking-tight">
            Analytics
          </h1>
          <p className="text-muted-foreground text-base">
            AI-powered insights and sales pipeline analytics
          </p>
        </div>
        <div className="flex items-center gap-3">
          <select
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value as PeriodKey)}
            className="px-3 py-2 border border-border rounded-lg bg-background text-foreground text-sm focus:outline-none focus:ring-2 focus:ring-primary"
          >
            <option value="7d">Last 7 days</option>
            <option value="30d">Last 30 days</option>
            <option value="90d">Last 90 days</option>
            <option value="ytd">Year to date</option>
          </select>

          {/* Analytics cache refresh */}
          <button
            onClick={handleRefreshAnalytics}
            className="inline-flex items-center gap-2 border border-border hover:bg-muted text-foreground font-medium py-2.5 px-4 rounded-lg transition-all active:scale-95 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2"
            aria-label="Refresh analytics data"
          >
            <span className="material-symbols-outlined text-lg">refresh</span>
            Refresh
          </button>

          {/* Export Dropdown */}
          <div className="relative" ref={exportMenuRef}>
            <button
              onClick={() => setExportMenuOpen(!exportMenuOpen)}
              className="inline-flex items-center gap-2 bg-primary hover:bg-primary/90 text-primary-foreground font-bold py-2.5 px-5 rounded-lg shadow-sm shadow-primary/30 transition-all active:scale-95 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 group"
            >
              <span className="material-symbols-outlined text-lg transition-transform group-hover:scale-110">
                download
              </span>{' '}
              Export
              <span
                className={`material-symbols-outlined text-sm transition-transform ${exportMenuOpen ? 'rotate-180' : ''}`}
              >
                expand_more
              </span>
            </button>

            {exportMenuOpen && (
              <div className="absolute right-0 mt-2 w-56 bg-card rounded-lg shadow-lg border border-border z-50 overflow-hidden">
                <div className="py-1">
                  <div className="px-3 py-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider border-b border-border">
                    CSV Export
                  </div>
                  <button
                    onClick={() => handleServerExport('overview')}
                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-foreground hover:bg-muted transition-colors"
                  >
                    <span className="material-symbols-outlined text-lg text-muted-foreground">
                      table_chart
                    </span>{' '}
                    Overview Metrics
                  </button>
                  <button
                    onClick={() => handleServerExport('funnel')}
                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-foreground hover:bg-muted transition-colors"
                  >
                    <span className="material-symbols-outlined text-lg text-muted-foreground">
                      waterfall_chart
                    </span>{' '}
                    Pipeline Funnel
                  </button>
                  <button
                    onClick={() => handleServerExport('sales')}
                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-foreground hover:bg-muted transition-colors"
                  >
                    <span className="material-symbols-outlined text-lg text-muted-foreground">
                      download
                    </span>{' '}
                    Sales Metrics
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Metrics Grid */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4 mb-6">
        {isLoading ? (
          <>
            <MetricCardSkeleton />
            <MetricCardSkeleton />
            <MetricCardSkeleton />
            <MetricCardSkeleton />
          </>
        ) : (
          <>
            <MetricCard
              title="Total Leads"
              value={overview?.totalLeads ?? 0}
              delta={overview?.leadDelta ?? 0}
              icon="people"
              formatValue={String}
              badge={leadStats ? `${leadStats.newThisMonth} new this month` : undefined}
            />
            <MetricCard
              title="Revenue"
              value={overview?.totalRevenue ?? 0}
              delta={overview?.revenueDelta ?? 0}
              icon="attach_money"
              formatValue={formatCurrency}
            />
            <MetricCard
              title="Open Opportunities"
              value={overview?.openOpportunities ?? 0}
              delta={overview?.openOpportunitiesDelta ?? 0}
              icon="handshake"
              formatValue={String}
            />
            <MetricCard
              title="Win Rate"
              value={overview?.winRate ?? 0}
              delta={overview?.winRateDelta ?? 0}
              icon="emoji_events"
              formatValue={(v) => `${v}%`}
              suffix="pp"
            />
          </>
        )}
      </div>

      {/* Charts Grid */}
      <div className="grid gap-6 lg:grid-cols-3 mb-6">
        {/* Pipeline Funnel */}
        <Card className="lg:col-span-2 p-6 bg-card border-border">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-semibold text-foreground">Pipeline Funnel</h2>
            {funnel && (
              <span className="text-sm text-muted-foreground">
                {funnel.overallConversionRate}% overall conversion
              </span>
            )}
          </div>

          <PipelineFunnelContent loading={funnelLoading} funnel={funnel} />
        </Card>

        {/* Lead Stats + Quick Info */}
        <Card className="p-6 bg-card border-border">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-semibold text-foreground">Lead Overview</h2>
          </div>
          {overview ? (
            <div className="space-y-4">
              <QuickStat
                label="New Contacts"
                value={overview.newContacts}
                delta={overview.newContactsDelta}
              />
              <QuickStat
                label="Win Rate"
                value={`${overview.winRate}%`}
                delta={overview.winRateDelta}
