        setLoading(false);
      }
    }
    fetchReport();
  }, [reportId]);

  const config = reportConfigs[reportId] || reportConfigs.lighthouse;

  const getStatusInfo = (status: string) => {
    switch (status) {
      case 'passing':
        return {
          icon: 'check_circle',
          color: 'text-emerald-500',
          bgColor: 'bg-emerald-100 dark:bg-emerald-900/30',
