function getRoleMessage(role: string): string {
  if (role === 'ADMIN') return 'You can manage team roles and permissions in Team Settings.';
  if (role === 'MANAGER') return 'To change roles or permissions, contact your Admin.';
  return 'To change your username or role, contact the System Administrator.';
}

function getThemeIcon(t: string): string {
  if (t === 'light') return 'light_mode';
  if (t === 'dark') return 'dark_mode';
  return 'contrast';
}

export default function AccountSettingsContent() {
  const { isLoading: authLoading, isAuthenticated } = useRequireAuth();

  // ÔöÇÔöÇÔöÇ Queries ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const profileQuery = trpc.user.getProfile.useQuery(undefined, {
    enabled: isAuthenticated,
    retry: false,
  });

  // ÔöÇÔöÇÔöÇ Mutations ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const utils = trpc.useUtils();
  const updateTimezoneMutation = trpc.user.updateTimezone.useMutation({
    onSuccess: () => utils.user.getProfile.invalidate(),
  });
  const updateProfileMutation = trpc.user.updateProfile.useMutation({
    onSuccess: () => utils.user.getProfile.invalidate(),
  });

  // ÔöÇÔöÇÔöÇ Local State ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [role, setRole] = useState('');
  const [phone, setPhone] = useState('');
  const [company, setCompany] = useState('');
  const [department, setDepartment] = useState('');
  const [location, setLocation] = useState('');
  const [website, setWebsite] = useState('');
  const [timezone, setTimezone] = useState('Europe/London');
  const [language, setLanguage] = useState('en-GB');
  const [dateFormat, setDateFormat] = useState('MM/DD/YYYY');
  const [emailNotifications, setEmailNotifications] = useState(true);
  const [desktopNotifications, setDesktopNotifications] = useState(true);
  const [isDirty, setIsDirty] = useState(false);
  const [photoDialogOpen, setPhotoDialogOpen] = useState(false);

  const { theme, setTheme } = useTheme();

  // Sync server data to local state
  useEffect(() => {
    if (profileQuery.data) {
      const data = profileQuery.data;
      if (data.givenName || data.familyName) {
        setFirstName(data.givenName ?? '');
        setLastName(data.familyName ?? '');
      } else {
        const parts = String(data.name ?? '').split(' ');
        setFirstName(parts[0] ?? '');
        setLastName(parts.slice(1).join(' '));
      }
      setEmail(data.email);
      setRole(String(data.role ?? ''));
      setPhone(data.phone ?? '');
      setCompany(data.company ?? '');
      setDepartment(data.department ?? '');
      setLocation(data.location ?? '');
      setWebsite(data.website ?? '');
      setTimezone(data.timezone ?? 'Europe/London');
      setLanguage(data.locale ?? 'en-GB');
    }
  }, [profileQuery.data]);

  // ÔöÇÔöÇÔöÇ Derived values ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const fullName = [firstName, lastName].filter(Boolean).join(' ') || 'User';
  const avatarSrc = profileQuery.data?.avatarUrl ?? null;
  const provider = profileQuery.data?.provider ?? null;
  const emailVerified = profileQuery.data?.emailVerified ?? false;
  const memberSince = profileQuery.data?.createdAt ?? null;
  const isLoading = authLoading || profileQuery.isLoading;
  const isSaving = updateTimezoneMutation.isPending || updateProfileMutation.isPending;
  const error = profileQuery.error;
  const username = email.split('@')[0] ?? '';

  // ÔöÇÔöÇÔöÇ Handlers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const markDirty = useCallback(() => setIsDirty(true), []);

  const handleSave = useCallback(async () => {
    try {
      await Promise.all([
        updateProfileMutation.mutateAsync({
          givenName: firstName || null,
          familyName: lastName || null,
          phone: phone || null,
          company: company || null,
          department: department || null,
          location: location || null,
          website: website || null,
          locale: language || null,
        }),
        updateTimezoneMutation.mutateAsync({ timezone }),
      ]);
      setIsDirty(false);
      toast({
        title: 'Settings saved',
        description: 'Your profile settings have been updated.',
      });
    } catch (err) {
      toast({
        title: 'Error saving settings',
        description: err instanceof Error ? err.message : 'An unexpected error occurred',
        variant: 'destructive',
      });
    }
  }, [
    firstName,
    lastName,
    phone,
    company,
    department,
    location,
    website,
    language,
    timezone,
    updateProfileMutation,
    updateTimezoneMutation,
  ]);

  const handleCancel = useCallback(() => {
    if (profileQuery.data) {
      const data = profileQuery.data;
      if (data.givenName || data.familyName) {
        setFirstName(data.givenName ?? '');
        setLastName(data.familyName ?? '');
      } else {
        const parts = String(data.name ?? '').split(' ');
        setFirstName(parts[0] ?? '');
        setLastName(parts.slice(1).join(' '));
      }
      setEmail(data.email);
      setPhone(data.phone ?? '');
      setCompany(data.company ?? '');
      setDepartment(data.department ?? '');
      setLocation(data.location ?? '');
      setWebsite(data.website ?? '');
      setTimezone(data.timezone ?? 'Europe/London');
      setLanguage(data.locale ?? 'en-GB');
      setIsDirty(false);
    }
  }, [profileQuery.data]);

  // ÔöÇÔöÇÔöÇ Early Returns (after all hooks) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  if (isLoading) return <AccountSettingsLoading />;

  if (error) {
    return (
      <div className="text-center py-16">
        <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-red-100 dark:bg-red-900/30 flex items-center justify-center">
          <span className="material-symbols-outlined text-red-600 dark:text-red-400 text-2xl">
            error
          </span>
        </div>
        <p className="text-lg font-semibold text-foreground mb-2">Failed to load profile</p>
        <p className="text-muted-foreground mb-6">{error.message}</p>
        <Button onClick={() => profileQuery.refetch()}>Try Again</Button>
      </div>
    );
  }

  return (
    <div className="pb-10">
      <PageHeader
        breadcrumbs={[
          { label: 'Dashboard', href: '/' },
          { label: 'Settings', href: '/settings' },
          { label: 'Profile Settings' },
        ]}
        title="Profile Settings"
        description="Manage your personal information and account preferences."
        className="mb-6"
      />

      {/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
