                    />
                    {regenerateBackupCodes.error && (
                      <p className="text-sm text-destructive">
                        {regenerateBackupCodes.error.message}
                      </p>
                    )}
                  </div>
                  <AlertDialogFooter>
                    <AlertDialogCancel
                      onClick={() => {
                        setRegenTotpCode('');
                        regenBtnRef.current?.focus();
