'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import { Button, Badge } from '@intelliflow/ui';
import type { DocumentSearchProps, DocumentStatus, DocumentClassification } from './types';

// =============================================================================
// DocumentSearch Component
// =============================================================================

const STATUS_OPTIONS: { value: DocumentStatus; label: string }[] = [
  { value: 'DRAFT', label: 'Draft' },
  { value: 'UNDER_REVIEW', label: 'In Review' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'SIGNED', label: 'Signed' },
  { value: 'ARCHIVED', label: 'Archived' },
  { value: 'SUPERSEDED', label: 'Superseded' },
];

const CLASSIFICATION_OPTIONS: { value: DocumentClassification; label: string }[] = [
  { value: 'PUBLIC', label: 'Public' },
  { value: 'INTERNAL', label: 'Internal' },
  { value: 'CONFIDENTIAL', label: 'Confidential' },
  { value: 'PRIVILEGED', label: 'Privileged' },
];

const FILE_TYPE_OPTIONS = [
  { value: 'pdf', label: 'PDF' },
  { value: 'word', label: 'Word' },
  { value: 'spreadsheet', label: 'Spreadsheet' },
  { value: 'image', label: 'Image' },
  { value: 'text', label: 'Text' },
];

const DEBOUNCE_MS = 300;

export function DocumentSearch({
  onSearch,
  onFilterChange,
  activeFilters,
  resultCount,
}: Readonly<DocumentSearchProps>) {
  const [searchValue, setSearchValue] = useState(activeFilters.query ?? '');
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // ÔöÇÔöÇÔöÇ Debounced Search ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      onSearch(searchValue);
    }, DEBOUNCE_MS);
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [searchValue, onSearch]);

  const handleSearchKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
        if (debounceRef.current) clearTimeout(debounceRef.current);
        onSearch(searchValue);
      }
    },
    [searchValue, onSearch]
  );

  const clearSearch = useCallback(() => {
    setSearchValue('');
    onSearch('');
  }, [onSearch]);

  // ÔöÇÔöÇÔöÇ Close dropdown on outside click ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setOpenDropdown(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // ÔöÇÔöÇÔöÇ Close dropdown on Escape ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setOpenDropdown(null);
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  // ÔöÇÔöÇÔöÇ Filter Toggles ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const toggleStatusFilter = useCallback(
    (status: DocumentStatus) => {
      const current = activeFilters.status ?? [];
      const updated = current.includes(status)
        ? current.filter((s) => s !== status)
        : [...current, status];
      onFilterChange({ ...activeFilters, status: updated.length > 0 ? updated : undefined });
    },
    [activeFilters, onFilterChange]
  );

  const toggleClassificationFilter = useCallback(
    (classification: DocumentClassification) => {
      const current = activeFilters.classification ?? [];
      const updated = current.includes(classification)
        ? current.filter((c) => c !== classification)
        : [...current, classification];
      onFilterChange({
        ...activeFilters,
        classification: updated.length > 0 ? updated : undefined,
      });
    },
    [activeFilters, onFilterChange]
  );

  const toggleFileTypeFilter = useCallback(
    (fileType: string) => {
      const current = activeFilters.fileType ?? [];
      const updated = current.includes(fileType)
        ? current.filter((ft) => ft !== fileType)
        : [...current, fileType];
      onFilterChange({ ...activeFilters, fileType: updated.length > 0 ? updated : undefined });
    },
    [activeFilters, onFilterChange]
  );

  const clearAllFilters = useCallback(() => {
    setSearchValue('');
    onSearch('');
    onFilterChange({});
  }, [onSearch, onFilterChange]);

  // ÔöÇÔöÇÔöÇ Active Filter Chips ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const hasActiveFilters =
    (activeFilters.status?.length ?? 0) > 0 ||
    (activeFilters.classification?.length ?? 0) > 0 ||
    (activeFilters.fileType?.length ?? 0) > 0 ||
    activeFilters.dateRange !== undefined;

  // ÔöÇÔöÇÔöÇ Dropdown Renderer ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const renderDropdown = (
    id: string,
    label: string,
    options: { value: string; label: string }[],
    activeValues: string[] | undefined,
    onToggle: (value: string) => void
  ) => {
    const isOpen = openDropdown === id;
    const count = activeValues?.length ?? 0;

    return (
      <div className="relative">
        <Button
          variant="outline"
          size="sm"
          onClick={() => setOpenDropdown(isOpen ? null : id)}
          aria-expanded={isOpen}
          aria-haspopup="listbox"
          className={count > 0 ? 'border-primary text-primary' : ''}
        >
          {label}
          {count > 0 && (
            <span className="ml-1.5 px-1.5 py-0.5 rounded-full text-xs bg-primary text-white">
              {count}
            </span>
          )}
          <span className="material-symbols-outlined text-[16px] ml-1">
            {isOpen ? 'expand_less' : 'expand_more'}
          </span>
        </Button>
        {isOpen && (
          <ul
            className="absolute top-full left-0 mt-1 w-56 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg shadow-lg z-20 py-2 list-none m-0 p-0"
            role="listbox"
            aria-label={`${label} filter options`}
          >
            {options.map((opt) => {
              const isActive = activeValues?.includes(opt.value) ?? false;
              return (
                <li key={opt.value} role="option" aria-selected={isActive}>
                  <label className="flex items-center gap-3 px-4 py-2 hover:bg-slate-50 dark:hover:bg-slate-700 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={isActive}
                      onChange={() => onToggle(opt.value)}
                      className="rounded border-slate-300"
                    />
                    <span className="text-sm text-slate-700 dark:text-slate-300">{opt.label}</span>
                  </label>
                </li>
              );
            })}
          </ul>
        )}
      </div>
    );
  };

  // ÔöÇÔöÇÔöÇ Render ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  return (
    <div className="space-y-3" data-testid="document-search">
      {/* Search Input + Filter Buttons */}
      <div className="flex flex-wrap items-center gap-3" ref={dropdownRef}>
        <div className="relative flex-1 min-w-[240px]">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 material-symbols-outlined text-[20px] text-slate-400">
            search
          </span>
          <input
            type="search"
            role="searchbox"
            value={searchValue}
            onChange={(e) => setSearchValue(e.target.value)}
            onKeyDown={handleSearchKeyDown}
            placeholder="Search documents..."
            className="w-full pl-10 pr-10 py-2 border border-slate-300 dark:border-slate-600 rounded-md bg-white dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-400"
            aria-label="Search documents"
          />
          {searchValue && (
            <button
              onClick={clearSearch}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              aria-label="Clear search"
            >
              <span className="material-symbols-outlined text-[18px]">close</span>
            </button>
          )}
        </div>

        {renderDropdown('status', 'Status', STATUS_OPTIONS, activeFilters.status, (v) =>
          toggleStatusFilter(v as DocumentStatus)
        )}
        {renderDropdown(
          'classification',
          'Classification',
          CLASSIFICATION_OPTIONS,
          activeFilters.classification,
          (v) => toggleClassificationFilter(v as DocumentClassification)
        )}
        {renderDropdown(
          'fileType',
          'File Type',
          FILE_TYPE_OPTIONS,
          activeFilters.fileType,
          toggleFileTypeFilter
        )}
      </div>

      {/* Active Filter Chips + Result Count */}
      <div className="flex flex-wrap items-center gap-2">
        {activeFilters.status?.map((status) => {
          const opt = STATUS_OPTIONS.find((o) => o.value === status);
          return (
            <Badge key={`status-${status}`} variant="secondary" className="flex items-center gap-1">
              {opt?.label ?? status}
              <button
                onClick={() => toggleStatusFilter(status)}
                className="ml-1 hover:text-red-500"
                aria-label={`Remove ${opt?.label ?? status} filter`}
              >
                <span className="material-symbols-outlined text-[14px]">close</span>
              </button>
            </Badge>
          );
        })}

        {activeFilters.classification?.map((cls) => {
          const opt = CLASSIFICATION_OPTIONS.find((o) => o.value === cls);
          return (
            <Badge key={`cls-${cls}`} variant="secondary" className="flex items-center gap-1">
              {opt?.label ?? cls}
              <button
                onClick={() => toggleClassificationFilter(cls)}
                className="ml-1 hover:text-red-500"
                aria-label={`Remove ${opt?.label ?? cls} filter`}
              >
                <span className="material-symbols-outlined text-[14px]">close</span>
              </button>
            </Badge>
          );
        })}

        {activeFilters.fileType?.map((ft) => {
          const opt = FILE_TYPE_OPTIONS.find((o) => o.value === ft);
          return (
            <Badge key={`ft-${ft}`} variant="secondary" className="flex items-center gap-1">
              {opt?.label ?? ft}
              <button
                onClick={() => toggleFileTypeFilter(ft)}
                className="ml-1 hover:text-red-500"
                aria-label={`Remove ${opt?.label ?? ft} filter`}
              >
                <span className="material-symbols-outlined text-[14px]">close</span>
              </button>
            </Badge>
          );
        })}

        {hasActiveFilters && (
          <button
            onClick={clearAllFilters}
            className="text-sm text-primary hover:text-primary/80 font-medium"
            data-testid="clear-all-filters"
          >
            Clear all
          </button>
        )}

        {resultCount !== undefined && (
          <span className="ml-auto text-sm text-slate-500" data-testid="result-count">
            {(() => {
              if (resultCount === 0) return 'No results';
              return `${resultCount} result${resultCount === 1 ? '' : 's'}`;
            })()}
          </span>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useRef, useCallback } from 'react';
import { Button, Card, toast } from '@intelliflow/ui';
import {
  formatFileSize,
  sanitizeFileName,
  ACCEPTED_EXTENSIONS,
  ACCEPTED_FILE_TYPES,
  MAX_FILE_SIZE_MB,
} from './document-utils';
import type { DocumentUploadProps, DocumentClassification } from './types';
import { trpc } from '@/lib/trpc';

// =============================================================================
// DocumentUpload Component
// =============================================================================

const CLASSIFICATION_OPTIONS: { value: DocumentClassification; label: string }[] = [
  { value: 'PUBLIC', label: 'Public' },
  { value: 'INTERNAL', label: 'Internal' },
  { value: 'CONFIDENTIAL', label: 'Confidential' },
  { value: 'PRIVILEGED', label: 'Privileged' },
];

export function DocumentUpload({
  tenantId: _tenantId,
  userId: _userId,
  relatedCaseId: _relatedCaseId,
  relatedContactId: _relatedContactId,
  onUploadComplete,
  onCancel,
  maxFileSizeMB = MAX_FILE_SIZE_MB,
}: Readonly<DocumentUploadProps>) {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  // tRPC mutation: creates the document record server-side (server generates storageKey per AC-011)
  const createDocumentMutation = trpc.documents.create.useMutation();
  const [isDragging, setIsDragging] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [classification, setClassification] = useState<DocumentClassification>('INTERNAL');
  const [tags, setTags] = useState('');
  const [fileHash, setFileHash] = useState<string | null>(null);

  // ÔöÇÔöÇÔöÇ File Validation ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const validateFile = useCallback(
    (file: Readonly<File>): string | null => {
      const extension = '.' + file.name.split('.').pop()?.toLowerCase();
      if (!ACCEPTED_EXTENSIONS.includes(extension) && !ACCEPTED_FILE_TYPES.includes(file.type)) {
        return `File type "${extension}" is not supported. Accepted: ${ACCEPTED_EXTENSIONS.join(', ')}`;
      }
      const maxBytes = maxFileSizeMB * 1024 * 1024;
      if (file.size > maxBytes) {
        return `File size (${formatFileSize(file.size)}) exceeds ${maxFileSizeMB}MB limit.`;
      }
      return null;
    },
    [maxFileSizeMB]
  );

  // ÔöÇÔöÇÔöÇ SHA-256 Hash ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const computeHash = useCallback(async (file: Readonly<File>): Promise<string> => {
    const buffer = await file.arrayBuffer();
    const hashBuffer = await crypto.subtle.digest('SHA-256', buffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
  }, []);

  // ÔöÇÔöÇÔöÇ File Selection ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const handleFileSelect = useCallback(
    async (file: File) => {
      const error = validateFile(file);
      if (error) {
        toast({ title: 'Invalid file', description: error, variant: 'destructive' });
        return;
      }
      setSelectedFile(file);
      setTitle((prev) => prev || sanitizeFileName(file.name.replace(/\.[^/.]+$/, '')));
      try {
        const hash = await computeHash(file);
        setFileHash(hash);
      } catch {
        // Hash computation failure is non-fatal
        setFileHash(null);
      }
    },
    [validateFile, computeHash]
  );

  const handleFileInputChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) handleFileSelect(file);
    },
    [handleFileSelect]
  );

  const removeFile = useCallback(() => {
    setSelectedFile(null);
    setFileHash(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  }, []);

  // ÔöÇÔöÇÔöÇ Drag & Drop ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
      const file = e.dataTransfer.files[0];
      if (file) handleFileSelect(file);
    },
    [handleFileSelect]
  );

  // ÔöÇÔöÇÔöÇ Submit ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const handleSubmit = useCallback(
    async (e: React.SyntheticEvent) => {
      e.preventDefault();
      if (!selectedFile || !title.trim()) {
        toast({
          title: 'Missing required fields',
          description: 'Please select a file and enter a title.',
          variant: 'destructive',
        });
        return;
      }

      setIsUploading(true);
      setUploadProgress(0);

      try {
        // Simulate progress (actual upload progress would come from XHR/fetch)
        const progressInterval = setInterval(() => {
          setUploadProgress((p) => Math.min(p + 10, 90));
        }, 200);

        // Server generates storageKey ÔÇö not client (SR-02)
        const tagArray = tags
          .split(',')
          .map((t) => t.trim())
          .filter(Boolean);

        // Derive a documentType from the file MIME type for the required API field.
        // The full document type selector UI is tracked in IFC-152.
        const mimeType = selectedFile.type || 'application/octet-stream';
        let documentType:
          | 'OTHER'
          | 'CONTRACT'
          | 'AGREEMENT'
          | 'EVIDENCE'
          | 'CORRESPONDENCE'
          | 'REPORT'
          | 'COURT_FILING'
          | 'MEMO';
        if (mimeType.startsWith('image/')) {
          documentType = 'EVIDENCE';
        } else if (
          mimeType.includes('pdf') ||
          mimeType.includes('msword') ||
          mimeType.includes('officedocument')
        ) {
          documentType = 'CONTRACT';
        } else {
          documentType = 'OTHER';
        }

        const contentHash = fileHash ?? '';
        if (!contentHash) {
          throw new Error('File hash not computed yet. Please wait a moment and try again.');
        }

        // Call documents.create ÔÇö server generates storageKey (AC-011)
        const result = await createDocumentMutation.mutateAsync({
          title: title.trim(),
          description: description.trim() || undefined,
          documentType: documentType,
          classification: classification,
          tags: tagArray,
          relatedCaseId: _relatedCaseId,
          relatedContactId: _relatedContactId,
          contentHash,
          mimeType,
          sizeBytes: selectedFile.size,
        });

        clearInterval(progressInterval);
        setUploadProgress(100);

        toast({ title: 'Document uploaded successfully' });
        onUploadComplete?.(result.id);
      } catch (err) {
        toast({
          title: 'Upload failed',
          description: err instanceof Error ? err.message : 'An error occurred during upload.',
          variant: 'destructive',
        });
      } finally {
        setIsUploading(false);
      }
    },
    [
      selectedFile,
      title,
      description,
      classification,
      tags,
      fileHash,
      _relatedCaseId,
      _relatedContactId,
      createDocumentMutation,
      onUploadComplete,
    ]
  );

  // ÔöÇÔöÇÔöÇ Cancel ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  const handleCancel = useCallback(() => {
    setSelectedFile(null);
    setFileHash(null);
    setTitle('');
    setDescription('');
    setClassification('INTERNAL');
    setTags('');
    setUploadProgress(0);
    onCancel?.();
  }, [onCancel]);

  // ÔöÇÔöÇÔöÇ Render ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {/* Drop Zone */}
      {}
      <div // NOSONAR ÔÇö file drop zone with nested interactive elements (Remove button); drag events require div wrapper
        role="button"
        tabIndex={0}
        aria-label="Drop files here or click to browse"
        className={`relative border-2 border-dashed rounded-lg p-8 text-center transition-colors cursor-pointer
          ${isDragging ? 'border-primary bg-primary/5' : 'border-slate-300 dark:border-slate-600 hover:border-primary/50'}
          ${selectedFile ? 'bg-emerald-50 dark:bg-emerald-900/10 border-emerald-300' : ''}`}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={() => fileInputRef.current?.click()}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            fileInputRef.current?.click();
          }
        }}
        data-testid="dropzone"
      >
        <input
          ref={fileInputRef}
          type="file"
          className="hidden"
          accept={ACCEPTED_EXTENSIONS.join(',')}
          onChange={handleFileInputChange}
          tabIndex={-1}
        />

        {selectedFile ? (
          <div className="space-y-2">
            <span className="material-symbols-outlined text-4xl text-emerald-500">
              check_circle
            </span>
            <p className="font-medium text-slate-900 dark:text-white">{selectedFile.name}</p>
            <p className="text-sm text-slate-500">{formatFileSize(selectedFile.size)}</p>
            {fileHash && (
              <p className="text-xs text-slate-400 font-mono truncate max-w-md mx-auto">
                SHA-256: {fileHash.slice(0, 16)}...
              </p>
            )}
            <Button
              type="button"
              variant="ghost"
              size="sm"
              onClick={(e) => {
                e.stopPropagation();
                removeFile();
              }}
              aria-label="Remove selected file"
            >
              Remove file
            </Button>
          </div>
        ) : (
          <div className="space-y-2">
            <span className="material-symbols-outlined text-4xl text-slate-400">cloud_upload</span>
            <p className="text-slate-700 dark:text-slate-300">
              Drag and drop a file here, or{' '}
              <span className="text-primary font-medium">click to browse</span>
            </p>
            <p className="text-sm text-slate-500">
              Accepted: {ACCEPTED_EXTENSIONS.join(', ')} (max {maxFileSizeMB}MB)
            </p>
          </div>
        )}
      </div>

      {/* Upload Progress */}
      {}
      {isUploading && (
        <div className="space-y-2">
          <div className="flex justify-between text-sm text-slate-600 dark:text-slate-400">
            <span>Uploading...</span>
            <span>{uploadProgress}%</span>
          </div>
          <progress
            value={uploadProgress}
            max={100}
            aria-label="Upload progress"
            className="w-full h-2 rounded-full appearance-none [&::-webkit-progress-bar]:rounded-full [&::-webkit-progress-bar]:bg-slate-200 dark:[&::-webkit-progress-bar]:bg-slate-700 [&::-webkit-progress-value]:rounded-full [&::-webkit-progress-value]:bg-primary [&::-moz-progress-bar]:bg-primary"
          />
        </div>
      )}
      {}

      {/* Metadata Form */}
      <Card className="p-6 space-y-4">
        <div>
          <label
            htmlFor="doc-title"
            className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1"
          >
            Title <span className="text-red-500">*</span>
          </label>
          <input
            id="doc-title"
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
            className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-md bg-white dark:bg-slate-800 text-slate-900 dark:text-white"
            placeholder="Enter document title"
            aria-required="true"
          />
        </div>

        <div>
          <label
            htmlFor="doc-classification"
            className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1"
          >
            Classification
          </label>
          <select
            id="doc-classification"
            value={classification}
            onChange={(e) => setClassification(e.target.value as DocumentClassification)}
            className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-md bg-white dark:bg-slate-800 text-slate-900 dark:text-white"
          >
            {CLASSIFICATION_OPTIONS.map((opt) => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label
            htmlFor="doc-tags"
            className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1"
          >
            Tags
          </label>
          <input
            id="doc-tags"
            type="text"
            value={tags}
            onChange={(e) => setTags(e.target.value)}
            className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-md bg-white dark:bg-slate-800 text-slate-900 dark:text-white"
            placeholder="Comma-separated tags (e.g., Legal, Contract, NDA)"
          />
        </div>

        <div>
          <label
            htmlFor="doc-description"
            className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1"
          >
            Description
          </label>
          <textarea
            id="doc-description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            rows={3}
            className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-md bg-white dark:bg-slate-800 text-slate-900 dark:text-white"
            placeholder="Optional description"
          />
        </div>
      </Card>

      {/* Actions */}
      <div className="flex justify-end gap-3">
        <Button type="button" variant="outline" onClick={handleCancel} disabled={isUploading}>
          Cancel
        </Button>
        <Button type="submit" disabled={!selectedFile || !title.trim() || isUploading}>
          {isUploading ? 'Uploading...' : 'Upload Document'}
        </Button>
      </div>
    </form>
  );
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { DocumentList, DocumentStatusBadge } from '../DocumentList';
