'use client';

import { useCallback, useRef, useState } from 'react';
import { Paperclip, X, FileText, Image, File, AlertCircle } from 'lucide-react';
import { cn } from '@/lib/utils';

interface AttachmentManagerProps {
  files: File[];
  onFilesChange: (files: File[]) => void;
  maxFileSize?: number; // bytes, default 25MB
  maxTotalSize?: number; // bytes, default 50MB
  className?: string;
}

function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

function getFileIcon(type: string) {
  if (type.startsWith('image/')) return Image;
  if (type.includes('pdf') || type.includes('document') || type.includes('text')) return FileText;
  return File;
}

export function AttachmentManager({
  files,
  onFilesChange,
  maxFileSize = 25 * 1024 * 1024,
  maxTotalSize = 50 * 1024 * 1024,
  className,
}: Readonly<AttachmentManagerProps>) {
  const [isDragOver, setIsDragOver] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const totalSize = files.reduce((sum, f) => sum + f.size, 0);
  const oversizedFiles = files.filter((f) => f.size > maxFileSize);
  const totalExceeded = totalSize > maxTotalSize;

  const addFiles = useCallback(
    (newFiles: FileList | File[]) => {
      const arr = Array.from(newFiles);
      onFilesChange([...files, ...arr]);
    },
    [files, onFilesChange]
  );

  const removeFile = useCallback(
    (index: number) => {
      onFilesChange(files.filter((_, i) => i !== index));
    },
    [files, onFilesChange]
  );

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(true);
  }, []);

  const handleDragLeave = useCallback(() => {
    setIsDragOver(false);
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragOver(false);
      if (e.dataTransfer.files.length > 0) {
        addFiles(e.dataTransfer.files);
      }
    },
    [addFiles]
  );

  return (
    <div className={cn('space-y-2', className)}>
      {/* Drop zone */}
      <div
        role="region"
        aria-label="File drop zone"
        data-testid="drop-zone"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={cn(
          'flex items-center justify-center rounded-md border-2 border-dashed p-3 text-sm text-muted-foreground transition-colors',
          isDragOver
            ? 'border-primary bg-primary/5 ring-2 ring-primary/20 highlight'
            : 'border-border'
        )}
      >
        <Paperclip className="mr-2 h-4 w-4" />
        <span>Drop files here or</span>
        <button
          type="button"
          aria-label="Attach file"
          className="ml-1 font-medium text-primary underline-offset-2 hover:underline focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1 rounded"
          onClick={() => fileInputRef.current?.click()}
        >
          browse
        </button>
        <input
          ref={fileInputRef}
          type="file"
          multiple
          hidden
          onChange={(e) => e.target.files && addFiles(e.target.files)}
        />
      </div>

      {/* File size errors */}
      {oversizedFiles.length > 0 && (
        <div className="flex items-center gap-1 text-xs text-destructive">
          <AlertCircle className="h-3.5 w-3.5" />
          <span>{oversizedFiles.map((f) => f.name).join(', ')} exceeds 25MB limit</span>
        </div>
      )}
      {totalExceeded && (
        <div className="flex items-center gap-1 text-xs text-destructive">
          <AlertCircle className="h-3.5 w-3.5" />
          <span>Total size exceeds 50MB limit ({formatFileSize(totalSize)})</span>
        </div>
      )}

      {/* File list */}
      {files.length > 0 && (
        <div className="space-y-1">
          <div className="flex items-center gap-1 text-xs text-muted-foreground">
            <Paperclip className="h-3 w-3" />
            <span>{files.length}</span> file{files.length === 1 ? '' : 's'} attached
          </div>
          {files.map((file, i) => {
            const Icon = getFileIcon(file.type);
            const isImage = file.type.startsWith('image/');
            return (
              <div
                key={`${file.name}-${i}`}
                className="flex items-center gap-2 rounded-md border border-border p-2 text-sm"
              >
                {isImage ? (
                  <img
                    src={URL.createObjectURL(file)}
                    alt={file.name}
                    className="h-8 w-8 rounded object-cover"
                  />
                ) : (
                  <Icon className="h-4 w-4 text-muted-foreground" />
                )}
                <div className="flex-1 truncate">
                  <div className="truncate font-medium">{file.name}</div>
                  <div className="text-xs text-muted-foreground">{formatFileSize(file.size)}</div>
                </div>
                <button
                  type="button"
                  aria-label={`Remove ${file.name}`}
                  className="inline-flex h-6 w-6 items-center justify-center rounded-md hover:bg-destructive/10 focus:outline-none focus:ring-2 focus:ring-ring"
                  onClick={() => removeFile(i)}
                >
                  <X className="h-3.5 w-3.5" />
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

'use client';

import { useCallback, useRef } from 'react';

const EMAIL_LIST_SKELETON_KEYS = [
  'em-skel-0',
  'em-skel-1',
  'em-skel-2',
  'em-skel-3',
  'em-skel-4',
] as const;
import { AlertCircle, RotateCcw } from 'lucide-react';
import { EmptyState } from '@intelliflow/ui';
import { cn } from '@/lib/utils';
import { SearchFilterBar } from '@/components/shared';
import { EmailListItem } from './EmailListItem';

const FILTER_CHIPS = [
  { id: 'all', label: 'All' },
  { id: 'unread', label: 'Unread' },
  { id: 'attachments', label: 'Attachments' },
];

interface EmailData {
  id: string;
  subject: string;
  textBody?: string;
  htmlBody?: string;
  from: { address: string; name?: string };
  receivedAt: string;
  isRead: boolean;
  labels?: string[];
  attachments: Array<{ filename: string; contentType: string; size: number; checksum: string }>;
}

interface EmailFilters {
  unread: boolean;
  hasAttachments: boolean;
}

interface EmailListProps {
  emails: EmailData[];
  /** Count of emails before client-side filters (unread/attachments) are applied. */
  totalUnfilteredCount: number;
  isLoading: boolean;
  isError: boolean;
  error: Error | null;
  selectedEmailId: string | null;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  onEmailSelect: (emailId: string) => void;
  onFilterChange: (filters: EmailFilters) => void;
  onRetry: () => void;
  filters: EmailFilters;
  className?: string;
}

export function EmailList({
  emails,
  totalUnfilteredCount,
  isLoading,
  isError,
  error: _error,
  selectedEmailId,
  searchQuery,
  onSearchChange,
  onEmailSelect,
  onFilterChange,
  onRetry,
  filters,
  className,
}: Readonly<EmailListProps>) {
  const listRef = useRef<HTMLUListElement>(null);

  let activeChip: string;
  if (filters.unread) {
    activeChip = 'unread';
  } else if (filters.hasAttachments) {
    activeChip = 'attachments';
  } else {
    activeChip = 'all';
  }

  const handleChipChange = useCallback(
    (chipId: string) => {
      onFilterChange({
        unread: chipId === 'unread',
        hasAttachments: chipId === 'attachments',
      });
    },
    [onFilterChange]
  );

  const handleListKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
      e.preventDefault();
      const items = listRef.current?.querySelectorAll('[role="option"]');
      if (!items?.length) return;

      const current = Array.from(items).indexOf(document.activeElement as Element);
      const direction = e.key === 'ArrowDown' ? 1 : -1;
      const next = Math.max(0, Math.min(items.length - 1, current + direction));
      (items[next] as HTMLElement).focus();
    }
  }, []);

  // Loading state
  if (isLoading) {
    return (
      <div className={cn('w-80 border-r border-border', className)}>
        <div className="p-3">
          <div className="h-9 rounded-md bg-muted animate-pulse" />
        </div>
        <div className="space-y-1 p-2">
          {EMAIL_LIST_SKELETON_KEYS.map((key) => (
            <div key={key} className="flex gap-3 rounded-lg p-3">
              <div className="h-9 w-9 rounded-full bg-muted animate-pulse" />
              <div className="flex-1 space-y-1.5">
                <div className="h-4 w-3/4 rounded bg-muted animate-pulse" />
                <div className="h-3 w-full rounded bg-muted animate-pulse" />
                <div className="h-3 w-1/2 rounded bg-muted animate-pulse" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // Error state
  if (isError) {
    return (
      <div
        className={cn(
          'flex w-80 flex-col items-center justify-center gap-3 border-r border-border p-4',
          className
        )}
      >
        <AlertCircle className="h-8 w-8 text-destructive" />
        <p className="text-sm text-muted-foreground">Failed to load emails</p>
        <button
          type="button"
          aria-label="Retry"
          className="inline-flex items-center gap-1 rounded-md bg-primary px-3 py-1.5 text-sm text-primary-foreground hover:bg-primary/90 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
          onClick={onRetry}
        >
          <RotateCcw className="h-3.5 w-3.5" /> Retry
        </button>
      </div>
    );
  }

  const isFilteredEmpty = emails.length === 0 && totalUnfilteredCount > 0;

  return (
    <div className={cn('flex w-80 flex-col border-r border-border', className)}>
      {/* Search & filter bar */}
      <SearchFilterBar
        searchValue={searchQuery}
        onSearchChange={onSearchChange}
        searchPlaceholder="Search emails..."
        searchAriaLabel="Search emails"
        filterChips={
          totalUnfilteredCount > 0
            ? { options: FILTER_CHIPS, value: activeChip, onChange: handleChipChange }
            : undefined
        }
        className="rounded-none border-0 border-b border-border shadow-none px-2 py-3.5 gap-3"
      />

      {/* Email list */}
      {emails.length === 0 ? (
        <div className="flex flex-1 flex-col items-center justify-center gap-2 p-4">
          {isFilteredEmpty ? (
            <>
              <EmptyState entity="emails" variant="filtered" phase="passive" />
              <button
                type="button"
                className="text-xs text-primary hover:underline focus:outline-none focus:ring-2 focus:ring-ring rounded"
                onClick={() => onFilterChange({ unread: false, hasAttachments: false })}
              >
                Clear filters
              </button>
            </>
          ) : (
            <EmptyState
              entity="emails"
              variant={searchQuery ? 'filtered' : 'folder'}
              phase="passive"
            />
          )}
        </div>
      ) : (
        <div role="none" onKeyDown={handleListKeyDown} className="flex-1 overflow-auto">
          <ul ref={listRef} aria-label="Email list" className="space-y-0.5 p-1 list-none">
            {emails.map((email) => (
              <EmailListItem
                key={email.id}
                email={email}
                isSelected={selectedEmailId === email.id}
                onSelect={onEmailSelect}
              />
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

'use client';

import { Paperclip } from 'lucide-react';
import { cn } from '@/lib/utils';
import { EMAIL_LABELS } from '@/components/sidebar/configs/EmailSidebarContent';
import { EntityHoverCard } from '@/components/shared';
import { useTimezoneContext } from '@/providers/TimezoneProvider';

interface EmailItemData {
  id: string;
  subject: string;
  textBody?: string;
  htmlBody?: string;
  from: { address: string; name?: string };
  receivedAt: string;
  isRead: boolean;
  labels?: string[];
  attachments: Array<{ filename: string; contentType: string; size: number; checksum: string }>;
}

interface EmailListItemProps {
  email: EmailItemData;
  isSelected: boolean;
  onSelect: (id: string) => void;
}

function formatRelativeTime(dateStr: string, formatDate: (input: Date | string) => string): string {
  const now = Date.now();
  const date = new Date(dateStr).getTime();
  const diffMs = now - date;
  const diffMin = Math.floor(diffMs / 60000);
  const diffHr = Math.floor(diffMs / 3600000);
  const diffDay = Math.floor(diffMs / 86400000);

  if (diffMin < 1) return 'just now';
  if (diffMin < 60) return `${diffMin}m`;
  if (diffHr < 24) return `${diffHr}h`;
  if (diffDay === 1) return 'yesterday';
  if (diffDay < 7) return `${diffDay}d`;
  return formatDate(dateStr);
}

function getInitial(name?: string, email?: string): string {
  if (name && name.length > 0) return name[0].toUpperCase();
  if (email && email.length > 0) return email[0].toUpperCase();
  return '?';
}

function getPreview(email: Readonly<EmailItemData>): string {
  if (email.textBody) return email.textBody.slice(0, 80);
  if (email.htmlBody) return email.htmlBody.replaceAll(/<[^<>]*>/g, '').slice(0, 80);
  return '';
}

export function EmailListItem({ email, isSelected, onSelect }: Readonly<EmailListItemProps>) {
  const { formatDate } = useTimezoneContext();
  return (
    <EntityHoverCard
      email={email.from.address}
      displayName={email.from.name}
      side="right"
      align="start"
    >
      {}
      <li
        role="option"
        aria-selected={isSelected}
        tabIndex={-1}
        className={cn(
          'flex cursor-pointer gap-3 rounded-lg px-3 py-2.5 transition-colors list-none',
          'hover:bg-accent/50',
          'focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1',
          isSelected && 'bg-primary/5 border-l-2 border-l-primary'
        )}
        onClick={() => onSelect(email.id)}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            onSelect(email.id);
          }
        }}
      >
        {/* Avatar */}
        <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-full bg-primary/10 text-sm font-medium text-primary">
          {getInitial(email.from.name, email.from.address)}
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center justify-between gap-2">
            <span className="truncate text-sm font-medium">
              {email.from.name || email.from.address}
            </span>
            <span className="shrink-0 text-xs text-muted-foreground">
              {formatRelativeTime(email.receivedAt, formatDate)}
            </span>
          </div>
          <div
            className={cn(
              'truncate text-sm',
              email.isRead ? 'text-muted-foreground' : 'font-semibold text-foreground'
            )}
          >
            {email.subject}
          </div>
          <div className="flex items-center gap-1">
            <span className="truncate text-xs text-muted-foreground">{getPreview(email)}</span>
            {email.labels && email.labels.length > 0 && (
              <span className="flex items-center gap-0.5 shrink-0">
                {email.labels.map((labelId) => {
                  const def = EMAIL_LABELS.find((l) => l.id === labelId);
                  return def ? (
                    <span
                      key={labelId}
                      className="h-2 w-2 rounded-full"
                      title={def.name}
                      style={{ backgroundColor: def.color }}
                    />
                  ) : null;
                })}
              </span>
            )}
            {email.attachments.length > 0 ? (
              <Paperclip
                data-testid="attachment-icon"
                className="h-3 w-3 shrink-0 text-muted-foreground"
              />
            ) : null}
          </div>
        </div>
      </li>
    </EntityHoverCard>
  );
}

'use client';

import { useId } from 'react';
import { ChevronDown, ChevronUp, Reply, ReplyAll, Forward, Paperclip } from 'lucide-react';
import { useTimezoneContext } from '@/providers/TimezoneProvider';
import { EntityHoverCard } from '@/components/shared';
import DOMPurify from 'isomorphic-dompurify';
import { cn } from '@/lib/utils';

interface EmailMessageData {
  id: string;
  subject: string;
  htmlBody?: string;
  textBody?: string;
  from: { address: string; name?: string };
  to: Array<{ address: string; name?: string }>;
  receivedAt: string;
  attachments: Array<{
    filename: string;
    contentType: string;
    size: number;
    checksum: string;
  }>;
}

interface EmailMessageProps {
  message: EmailMessageData;
  isExpanded: boolean;
  onToggle: () => void;
  onReply: (messageId: string) => void;
  onReplyAll: (messageId: string) => void;
  onForward: (messageId: string) => void;
}

function getInitial(name?: string, address?: string): string {
  if (name) return name[0].toUpperCase();
  if (address) return address[0].toUpperCase();
  return '?';
}

export function EmailMessage({
  message,
  isExpanded,
  onToggle,
  onReply,
  onReplyAll,
  onForward,
}: Readonly<EmailMessageProps>) {
  const { timezone } = useTimezoneContext();
  const headingId = useId();
  const contentId = useId();

  return (
    <article className="rounded-lg border border-border">
      {/* Header ÔÇö always visible (div instead of button to allow nested interactive elements) */}
      {}
      <div
        role="button"
        tabIndex={0}
        aria-expanded={isExpanded}
        aria-controls={contentId}
        aria-label={isExpanded ? 'Collapse message' : 'Expand message'}
        className={cn(
          'flex w-full items-center gap-3 px-4 py-3 text-left transition-colors cursor-pointer',
          'hover:bg-accent/50',
          'focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1 rounded-t-lg',
          !isExpanded && 'rounded-b-lg'
        )}
        onClick={onToggle}
        onKeyDown={(e) => {
