'use client';

import { useCallback, useRef, useState } from 'react';
import {
  Bold,
  Italic,
  Underline,
  List,
  ListOrdered,
  Link as LinkIcon,
  RemoveFormatting,
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface FormatToolbarProps {
  onFormat: (command: string, value?: string) => void;
  activeFormats?: string[];
  className?: string;
}

const BUTTONS = [
  { command: 'bold', label: 'Bold', icon: Bold, shortcut: 'Ctrl+B', toggle: true },
  { command: 'italic', label: 'Italic', icon: Italic, shortcut: 'Ctrl+I', toggle: true },
  { command: 'underline', label: 'Underline', icon: Underline, shortcut: 'Ctrl+U', toggle: true },
  { command: 'insertOrderedList', label: 'Ordered list', icon: ListOrdered, toggle: true },
  { command: 'insertUnorderedList', label: 'Unordered list', icon: List, toggle: true },
  { command: 'createLink', label: 'Link', icon: LinkIcon, toggle: false },
  { command: 'removeFormat', label: 'Clear formatting', icon: RemoveFormatting, toggle: false },
] as const;

export function FormatToolbar({
  onFormat,
  activeFormats = [],
  className,
}: Readonly<FormatToolbarProps>) {
  const [focusIndex, setFocusIndex] = useState(0);
  const [showLinkInput, setShowLinkInput] = useState(false);
  const [linkUrl, setLinkUrl] = useState('');
  const buttonRefs = useRef<(HTMLButtonElement | null)[]>([]);
  const linkInputRef = useRef<HTMLInputElement>(null);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') {
        e.preventDefault();
        const direction = e.key === 'ArrowRight' ? 1 : -1;
        const next = (focusIndex + direction + BUTTONS.length) % BUTTONS.length;
        setFocusIndex(next);
        buttonRefs.current[next]?.focus();
      }
    },
    [focusIndex]
  );

  const handleButtonClick = useCallback(
    (command: string) => {
      if (command === 'createLink') {
        setShowLinkInput(true);
        setLinkUrl('https://');
        // Focus the input after render
        setTimeout(() => linkInputRef.current?.focus(), 0);
      } else {
        onFormat(command);
      }
    },
    [onFormat]
  );

  const handleLinkSubmit = useCallback(() => {
    const url = linkUrl.trim();
    if (url && url !== 'https://') {
      onFormat('createLink', url);
    }
    setShowLinkInput(false);
    setLinkUrl('');
  }, [linkUrl, onFormat]);

  const handleLinkCancel = useCallback(() => {
    setShowLinkInput(false);
    setLinkUrl('');
  }, []);

  return (
    <div className={cn('border-b border-border', className)}>
      <div
        role="toolbar"
        aria-label="Text formatting"
        aria-orientation="horizontal"
        className="flex items-center gap-0.5 p-1"
        onKeyDown={handleKeyDown}
      >
        {BUTTONS.map((btn, i) => {
          const Icon = btn.icon;
          const isActive = activeFormats.includes(btn.command);

          return (
            <button
              key={btn.command}
              ref={(el) => {
                buttonRefs.current[i] = el;
              }}
              type="button"
              tabIndex={i === focusIndex ? 0 : -1}
              aria-label={btn.label}
              aria-pressed={btn.toggle ? isActive : undefined}
              title={
                'shortcut' in btn && btn.shortcut ? `${btn.label} (${btn.shortcut})` : btn.label
              }
              className={cn(
                'inline-flex h-8 w-8 items-center justify-center rounded-md text-sm',
                'hover:bg-accent hover:text-accent-foreground',
                'focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1',
                'transition-colors',
                isActive && 'bg-primary/15 text-primary ring-1 ring-primary/30'
              )}
              // Prevent stealing focus from the contentEditable editor
              onMouseDown={(e) => e.preventDefault()}
              onClick={() => handleButtonClick(btn.command)}
            >
              <Icon className="h-4 w-4" />
            </button>
          );
        })}
      </div>

      {/* Inline link URL input */}
      {showLinkInput && (
        <div className="flex items-center gap-2 border-t border-border px-2 py-1.5">
          <LinkIcon className="h-3.5 w-3.5 text-muted-foreground flex-shrink-0" />
          <input
            ref={linkInputRef}
            type="url"
            placeholder="https://example.com"
            value={linkUrl}
            onChange={(e) => setLinkUrl(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleLinkSubmit();
              }
              if (e.key === 'Escape') {
                handleLinkCancel();
              }
            }}
            className="flex-1 bg-transparent text-sm placeholder:text-muted-foreground focus:outline-none"
          />
          <button
            type="button"
            className="rounded px-2 py-0.5 text-xs font-medium bg-primary text-primary-foreground hover:bg-primary/90"
            onClick={handleLinkSubmit}
          >
            Apply
          </button>
          <button
            type="button"
            className="rounded px-2 py-0.5 text-xs text-muted-foreground hover:text-foreground"
            onClick={handleLinkCancel}
          >
            Cancel
          </button>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useRef, useCallback, useMemo } from 'react';
import { Send, X, AlertCircle } from 'lucide-react';
import DOMPurify from 'isomorphic-dompurify';
import { trpc } from '@/lib/trpc';
import { toast } from '@intelliflow/ui';
import { cn } from '@/lib/utils';

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

type InlineMode = 'reply' | 'replyAll' | 'forward';

interface InlineComposeProps {
  mode: InlineMode;
  originalMessage: {
    id: string;
    subject: string;
    htmlBody?: string;
    textBody?: string;
    from: { address: string; name?: string };
    to: Array<{ address: string; name?: string }>;
  };
  onSent: () => void;
  onDiscard: () => void;
  className?: string;
}

function getSubject(mode: InlineMode, original: string): string {
  if (mode === 'forward') {
    return original.startsWith('Fwd:') ? original : `Fwd: ${original}`;
  }
  return original.startsWith('Re:') ? original : `Re: ${original}`;
}

function getRecipients(
  mode: InlineMode,
  from: { address: string; name?: string },
  to: Array<{ address: string; name?: string }>
): { to: string[]; cc: string[] } {
  if (mode === 'reply') {
    return { to: [from.address], cc: [] };
  }
  if (mode === 'replyAll') {
    const cc = to.filter((r) => r.address !== from.address).map((r) => r.address);
    return { to: [from.address], cc };
  }
  // forward ÔÇö user must add recipients
  return { to: [], cc: [] };
}

export function InlineCompose({
  mode,
  originalMessage,
  onSent,
  onDiscard,
  className,
}: Readonly<InlineComposeProps>) {
  const recipients = getRecipients(mode, originalMessage.from, originalMessage.to);
  const [forwardTo, setForwardTo] = useState('');
  const [hasBody, setHasBody] = useState(false);
  const bodyRef = useRef<HTMLDivElement>(null);
  const sendMutation = trpc.email.sendEmail.useMutation();

  const quotedBody =
    mode === 'forward' && originalMessage.htmlBody
      ? `<br><div style="border-left:2px solid #ccc;padding-left:8px;color:#666"><p><strong>Forwarded message:</strong></p>${DOMPurify.sanitize(originalMessage.htmlBody)}</div>`
      : '';

  // Track body content changes from contentEditable
  const handleBodyInput = useCallback(() => {
    const html = bodyRef.current?.innerHTML ?? '';
    const text = html.replace(/<[^>]*>/g, '').trim();
    setHasBody(text.length > 0);
  }, []);

  // Validation state
  const validationErrors = useMemo(() => {
    const errors: string[] = [];
    if (mode === 'forward') {
      const trimmed = forwardTo.trim();
      if (!trimmed) {
        errors.push('Recipient email is required');
      } else if (!EMAIL_REGEX.test(trimmed)) {
        errors.push('Enter a valid email address');
      }
    }
    if (!hasBody) {
      errors.push('Message body is required');
    }
    return errors;
  }, [mode, forwardTo, hasBody]);

  const canSend = validationErrors.length === 0 && !sendMutation.isPending;

  const handleSend = useCallback(async () => {
    // Re-check body from DOM in case state is stale
    const body = bodyRef.current?.innerHTML ?? '';
    const plainText = body.replace(/<[^>]*>/g, '').trim();
    if (!plainText) {
      toast({ title: 'Message body is required', variant: 'destructive' });
      return;
    }

    const to = mode === 'forward' ? [forwardTo.trim()] : recipients.to;
    if (to.length === 0 || !to[0]) {
      toast({ title: 'At least one recipient is required', variant: 'destructive' });
      return;
    }

    if (mode === 'forward' && !EMAIL_REGEX.test(to[0])) {
      toast({ title: 'Enter a valid email address', variant: 'destructive' });
      return;
    }

    try {
      await sendMutation.mutateAsync({
        to,
        cc: recipients.cc.length > 0 ? recipients.cc : undefined,
        subject: getSubject(mode, originalMessage.subject),
        htmlBody: body,
        threadId: originalMessage.id,
      });
      toast({ title: mode === 'forward' ? 'Email forwarded' : 'Reply sent' });
      onSent();
    } catch {
      toast({ title: 'Failed to send', variant: 'destructive' });
    }
  }, [mode, forwardTo, recipients, originalMessage, sendMutation, onSent]);

  let modeLabel: string;
  if (mode === 'replyAll') modeLabel = 'Reply All';
  else if (mode === 'forward') modeLabel = 'Forward';
  else modeLabel = 'Reply';

  return (
    <div className={cn('rounded-lg border border-primary/30 bg-card', className)}>
      {/* Header */}
      <div className="flex items-center justify-between border-b border-border px-3 py-2">
        <span className="text-xs font-medium text-muted-foreground">{modeLabel}</span>
        <button
          type="button"
          aria-label="Discard"
          className="inline-flex h-6 w-6 items-center justify-center rounded hover:bg-accent"
          onClick={onDiscard}
        >
          <X className="h-3.5 w-3.5" />
        </button>
      </div>

      {/* Recipients */}
      <div className="border-b border-border px-3 py-1.5">
        {mode === 'forward' ? (
          <div className="flex items-center gap-2">
            <span className="text-xs text-muted-foreground">To</span>
            <input
              type="email"
              aria-label="Forward to"
              placeholder="recipient@example.com"
              value={forwardTo}
              onChange={(e) => setForwardTo(e.target.value)}
              className="flex-1 bg-transparent text-xs placeholder:text-muted-foreground focus:outline-none"
            />
          </div>
        ) : (
          <p className="text-xs text-muted-foreground">
            To: {recipients.to.join(', ')}
            {recipients.cc.length > 0 && ` | CC: ${recipients.cc.join(', ')}`}
          </p>
        )}
      </div>

      {/* Body */}
      <div className="px-3 py-2">
        {}
        <div
          ref={bodyRef}
          role="textbox"
          tabIndex={0}
          aria-label="Reply body"
          aria-multiline="true"
          contentEditable
          suppressContentEditableWarning
          onInput={handleBodyInput}
          className="min-h-[80px] max-h-[200px] overflow-y-auto text-sm focus:outline-none prose prose-sm max-w-none"
          dangerouslySetInnerHTML={quotedBody ? { __html: quotedBody } : undefined}
        />
      </div>

      {/* Validation hints */}
      {validationErrors.length > 0 && (
        <div
          className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-destructive"
          role="alert"
        >
          <AlertCircle className="h-3.5 w-3.5 shrink-0" />
          <span>{validationErrors[0]}</span>
        </div>
      )}

      {/* Actions */}
      <div className="flex items-center gap-2 border-t border-border px-3 py-2">
        <button
          type="button"
          aria-label={`Send ${modeLabel.toLowerCase()}`}
          disabled={!canSend}
          className={cn(
            'inline-flex items-center gap-1.5 rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground',
            'hover:bg-primary/90 focus:outline-none focus:ring-2 focus:ring-ring',
            'disabled:opacity-50 disabled:cursor-not-allowed'
          )}
          onClick={handleSend}
        >
          <Send className="h-3.5 w-3.5" />
          Send
        </button>
        <button
          type="button"
          aria-label="Discard reply"
          className="inline-flex items-center gap-1 rounded-md px-2.5 py-1.5 text-xs text-muted-foreground hover:bg-accent"
          onClick={onDiscard}
        >
          Discard
        </button>
      </div>
    </div>
  );
}

'use client';

import { useState, useRef, useCallback, useId, useMemo, useEffect } from 'react';
import { X, User, Briefcase, Mail } from 'lucide-react';
import { trpc } from '@/lib/trpc';
import { useDebounce } from '@/hooks/useDebounce';
import { cn } from '@/lib/utils';

export interface Recipient {
  name: string;
  email: string;
}

type SuggestionSource = 'contact' | 'lead' | 'email';

interface ScoredSuggestion {
  name: string;
  email: string;
  source: SuggestionSource;
  detail?: string;
  score: number;
}

interface RecipientPickerProps {
  label: string;
  value: Recipient[];
  onChange: (recipients: Recipient[]) => void;
  className?: string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@.]+\.[^\s@.]+$/;

const SOURCE_CONFIG: Record<SuggestionSource, { icon: typeof User; label: string; color: string }> =
  {
    contact: { icon: User, label: 'Contact', color: 'text-blue-500 bg-blue-500/10' },
    lead: { icon: Briefcase, label: 'Lead', color: 'text-amber-500 bg-amber-500/10' },
    email: { icon: Mail, label: 'Email', color: 'text-emerald-500 bg-emerald-500/10' },
  };

function getTypeScore(source: SuggestionSource): number {
  if (source === 'contact') return 1.0;
  if (source === 'lead') return 0.6;
  return 0.3;
}

/**
 * Field Autocomplete Algorithm
 * score = w1┬Àstring_match + w2┬Àcontact_type + w3┬Àcompleteness + w4┬Àprefix_match
 *
 * Weights:
 *   string_match  (0.45) ÔÇö how well the query matches name or email
 *   contact_type  (0.25) ÔÇö contacts > leads > email-only
 *   completeness  (0.15) ÔÇö full name > email-only
 *   prefix_match  (0.15) ÔÇö exact prefix on any token scores highest
 */
function computeScore(
  query: string,
  email: string,
  name: string,
  source: SuggestionSource
): number {
  const q = query.toLowerCase();
  const e = email.toLowerCase();
  const n = name.toLowerCase();

  // String match (0ÔÇô1)
  let stringMatch = 0;
  if (e === q || n === q) {
    stringMatch = 1.0;
  } else if (e.startsWith(q) || n.startsWith(q)) {
    stringMatch = 0.9;
  } else {
    // Check individual name tokens
    const tokens = n.split(/\s+/);
    if (tokens.some((t) => t.startsWith(q))) {
      stringMatch = 0.8;
    } else if (e.includes(q) || n.includes(q)) {
      stringMatch = 0.5;
    }
  }

  // Contact type (0ÔÇô1)
  const typeScore = getTypeScore(source);

  // Completeness ÔÇö has real name vs just email (0ÔÇô1)
  const completeness = name && name !== email ? 1.0 : 0.3;

  // Prefix match bonus ÔÇö exact email prefix before @ (0ÔÇô1)
  const emailLocal = e.split('@')[0] ?? '';
  const prefixMatch = emailLocal.startsWith(q) ? 1.0 : 0;

  return 0.45 * stringMatch + 0.25 * typeScore + 0.15 * completeness + 0.15 * prefixMatch;
}

export function RecipientPicker({
  label,
  value,
  onChange,
  className,
}: Readonly<RecipientPickerProps>) {
  const [inputValue, setInputValue] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const [highlightIndex, setHighlightIndex] = useState(-1);
  const [error, setError] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const suggestionsId = useId();
  const suggestionsHintId = useId();
  const inputId = useId();
  const nativeSuggestionsId = useId();

  const debouncedQuery = useDebounce(inputValue, 200);
  const queryEnabled = debouncedQuery.length >= 1;

  // Search contacts (fast endpoint, tenant-scoped, <200ms KPI)
  const contactsQuery = trpc.contact.search.useQuery(
    { query: debouncedQuery, limit: 10 },
    { enabled: queryEnabled }
  );

  // Search leads
  const leadsQuery = trpc.lead.list.useQuery(
    { search: debouncedQuery, limit: 10 },
    { enabled: queryEnabled }
  );

  // Merge, deduplicate, score, and sort suggestions
  const suggestions = useMemo((): ScoredSuggestion[] => {
    if (!debouncedQuery) return [];

    const all: ScoredSuggestion[] = [];
    const seen = new Set(value.map((r) => r.email.toLowerCase()));

    // Add contacts
    for (const c of contactsQuery.data?.contacts ?? []) {
      const email = c.email?.toLowerCase();
      if (!email || seen.has(email)) continue;
      seen.add(email);
      const name = `${c.firstName ?? ''} ${c.lastName ?? ''}`.trim();
      all.push({
        name: name || email,
        email: c.email,
        source: 'contact',
        detail: c.title ?? c.department ?? undefined,
        score: computeScore(debouncedQuery, c.email, name, 'contact'),
      });
    }

    // Add leads (skip if already seen as contact)
    for (const l of (leadsQuery.data as { data?: Array<Record<string, unknown>> })?.data ?? []) {
      const email = (l.email as string)?.toLowerCase();
      if (!email || seen.has(email)) continue;
      seen.add(email);
      const name = `${(l.firstName as string) ?? ''} ${(l.lastName as string) ?? ''}`.trim();
      all.push({
        name: name || email,
        email: l.email as string,
        source: 'lead',
        detail: (l.company as string) ?? undefined,
        score: computeScore(debouncedQuery, l.email as string, name, 'lead'),
      });
    }

    return all.sort((a, b) => b.score - a.score).slice(0, 8);
  }, [contactsQuery.data, leadsQuery.data, debouncedQuery, value]);

  const isLoading = queryEnabled && (contactsQuery.isLoading || leadsQuery.isLoading);

  useEffect(() => {
    if (!isOpen) return;

    const handlePointerDown = (event: MouseEvent) => {
      if (containerRef.current?.contains(event.target as Node)) return;
      setIsOpen(false);
      setHighlightIndex(-1);
    };

    document.addEventListener('mousedown', handlePointerDown);
    return () => document.removeEventListener('mousedown', handlePointerDown);
  }, [isOpen]);

  const addRecipient = useCallback(
    (recipient: Recipient) => {
      onChange([...value, recipient]);
      setInputValue('');
      setIsOpen(false);
      setHighlightIndex(-1);
      setError(null);
      inputRef.current?.focus();
    },
    [value, onChange]
  );

  const removeRecipient = useCallback(
    (index: number) => {
      onChange(value.filter((_, i) => i !== index));
    },
    [value, onChange]
  );

  const addSuggestionRecipient = useCallback(
    (suggestion: Pick<ScoredSuggestion, 'name' | 'email'>) => {
      addRecipient({ name: suggestion.name, email: suggestion.email });
    },
    [addRecipient]
  );

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
    setIsOpen(e.target.value.length > 0);
    setHighlightIndex(-1);
    setError(null);
  }, []);

  const handleEnterKey = useCallback(() => {
    if (highlightIndex >= 0 && highlightIndex < suggestions.length) {
      const s = suggestions[highlightIndex];
      addSuggestionRecipient(s);
      return;
    }

    const trimmed = inputValue.trim();
    if (!trimmed) return;

    const exactMatch = suggestions.find((suggestion) => {
      const normalizedInput = trimmed.toLowerCase();
      return (
        suggestion.email.toLowerCase() === normalizedInput ||
        suggestion.name.toLowerCase() === normalizedInput
      );
    });

    if (exactMatch) {
      addSuggestionRecipient(exactMatch);
      return;
    }

    if (EMAIL_REGEX.test(trimmed)) {
      addRecipient({ name: trimmed, email: trimmed });
    } else {
      setError('Invalid email address');
    }
  }, [highlightIndex, suggestions, inputValue, addRecipient, addSuggestionRecipient]);

  const openDropdownIfNeeded = useCallback(() => {
    if (!isOpen && inputValue) setIsOpen(true);
  }, [isOpen, inputValue]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        handleEnterKey();
      } else if (e.key === 'Backspace') {
        if (!inputValue && value.length > 0) onChange(value.slice(0, -1));
      } else if (e.key === 'ArrowDown') {
        e.preventDefault();
        openDropdownIfNeeded();
        setHighlightIndex((prev) => (prev < suggestions.length - 1 ? prev + 1 : prev));
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setHighlightIndex((prev) => (prev > 0 ? prev - 1 : 0));
      } else if (e.key === 'Escape') {
        setIsOpen(false);
        setHighlightIndex(-1);
      }
    },
    [handleEnterKey, inputValue, value, onChange, openDropdownIfNeeded, suggestions.length]
  );

  const highlightedSuggestion = highlightIndex >= 0 ? suggestions[highlightIndex] : undefined;
  let suggestionsHint = `Type to search ${label.toLowerCase()} suggestions.`;
  if (isLoading) {
    suggestionsHint = `Searching ${label.toLowerCase()} suggestions.`;
  } else if (highlightedSuggestion) {
    suggestionsHint = `${suggestions.length} suggestions available. ${highlightedSuggestion.name}, ${highlightedSuggestion.email} highlighted. Press Enter to add.`;
  } else if (suggestions.length > 0) {
    suggestionsHint = `${suggestions.length} suggestions available. Use arrow keys to choose and Enter to add.`;
  } else if (inputValue) {
    suggestionsHint = `No ${label.toLowerCase()} suggestions found.`;
  }

  return (
    <div ref={containerRef} className={cn('relative', className)}>
      <label htmlFor={inputId} className="sr-only">
        {label}
      </label>
      <div
        className={cn(
          'flex flex-wrap items-center gap-1 rounded-md border border-input px-2 py-1.5 text-sm',
          'focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-1'
        )}
      >
        {value.map((recipient, i) => (
          <span
            key={recipient.email}
            className="inline-flex items-center gap-1 rounded-full bg-secondary px-2 py-0.5 text-xs"
          >
            <span>{recipient.name || recipient.email}</span>
            <button
              type="button"
              aria-label={`Remove ${recipient.name || recipient.email}`}
              className="inline-flex h-3.5 w-3.5 items-center justify-center rounded-full hover:bg-destructive/20 focus:outline-none focus:ring-1 focus:ring-ring"
              onClick={() => removeRecipient(i)}
            >
              <X className="h-2.5 w-2.5" />
            </button>
          </span>
        ))}
        <input
          ref={inputRef}
          id={inputId}
          type="text"
          value={inputValue}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          onFocus={() => inputValue && setIsOpen(true)}
          placeholder="Add recipient..."
          autoComplete="off"
          list={nativeSuggestionsId}
          aria-controls={suggestionsId}
          aria-describedby={suggestionsHintId}
          className="min-w-[120px] flex-1 bg-transparent outline-none placeholder:text-muted-foreground"
        />
      </div>

      {error ? <p className="mt-1 text-xs text-destructive">{error}</p> : null}
      <p id={suggestionsHintId} aria-live="polite" className="sr-only">
        {suggestionsHint}
      </p>
      {suggestions.length > 0 ? (
        <datalist id={nativeSuggestionsId}>
          {suggestions.map((suggestion) => {
            const config = SOURCE_CONFIG[suggestion.source];
            const detail = suggestion.detail ? `, ${suggestion.detail}` : '';

            return (
              <option
                key={`${suggestion.source}-${suggestion.email}-native`}
                value={suggestion.email}
                label={`${suggestion.name} (${config.label}${detail})`}
              />
            );
          })}
        </datalist>
      ) : null}

      {isOpen && (suggestions.length > 0 || isLoading) ? (
        <ul
          id={suggestionsId}
          aria-label={`${label} suggestions`}
          className="absolute z-50 mt-1 max-h-64 w-full overflow-auto rounded-md border border-border bg-popover p-1 shadow-md"
        >
          {isLoading && suggestions.length === 0 && (
            <li className="px-2 py-2 text-sm text-muted-foreground">Searching...</li>
          )}
          {suggestions.map((suggestion, i) => {
            const config = SOURCE_CONFIG[suggestion.source];
            const Icon = config.icon;

            return (
              <li key={`${suggestion.source}-${suggestion.email}`}>
                <button
                  type="button"
                  className={cn(
                    'flex w-full items-center gap-2.5 rounded-sm px-2 py-2 text-left text-sm',
                    i === highlightIndex && 'bg-accent text-accent-foreground'
                  )}
                  data-highlighted={i === highlightIndex ? 'true' : undefined}
                  onFocus={() => setHighlightIndex(i)}
                  onMouseEnter={() => setHighlightIndex(i)}
                  onMouseDown={(event) => {
                    event.preventDefault();
                    addSuggestionRecipient(suggestion);
                  }}
                  onClick={() => addSuggestionRecipient(suggestion)}
                >
                  <div
                    className={cn(
                      'flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full',
                      config.color
                    )}
                  >
                    <Icon className="h-3.5 w-3.5" />
                  </div>

                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2">
                      <span className="truncate font-medium">{suggestion.name}</span>
                      <span
                        className={cn(
                          'inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium',
                          config.color
                        )}
                      >
                        {config.label}
                      </span>
                    </div>
                    <div className="truncate text-xs text-muted-foreground">
                      {suggestion.email}
                      {suggestion.detail && (
                        <span className="ml-1.5 text-muted-foreground/70">
                          &middot; {suggestion.detail}
                        </span>
                      )}
                    </div>
                  </div>
                </button>
              </li>
            );
          })}
        </ul>
      ) : null}
    </div>
  );
}

'use client';

import { useState, useMemo, useCallback } from 'react';
import { LayoutTemplate, Search, ChevronDown } from 'lucide-react';
import { trpc } from '@/lib/trpc';
import { cn } from '@/lib/utils';

interface Template {
  id: string;
  name: string;
  subject: string;
  body: string;
  category: string;
  variables: string[];
}

interface TemplateSelectorProps {
  onSelect: (template: Template) => void;
  currentBody?: string;
  className?: string;
}

export function TemplateSelector({
  onSelect,
  currentBody = '',
  className,
}: Readonly<TemplateSelectorProps>) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [pendingTemplate, setPendingTemplate] = useState<Template | null>(null);
  const [highlightIndex, setHighlightIndex] = useState(-1);

  const { data: templates = [] } = trpc.email.listTemplates.useQuery(
    { search: searchQuery },
    { enabled: true }
  );

  const filteredTemplates = useMemo(() => {
    if (!searchQuery) return templates as Template[];
    return (templates as Template[]).filter((t) =>
      t.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [templates, searchQuery]);

  const handleSelect = useCallback(
    (template: Template) => {
      if (currentBody.trim()) {
        setPendingTemplate(template);
      } else {
        onSelect(template);
        setIsOpen(false);
      }
    },
    [currentBody, onSelect]
  );

  const confirmReplace = useCallback(() => {
    if (pendingTemplate) {
      onSelect(pendingTemplate);
      setPendingTemplate(null);
      setIsOpen(false);
    }
  }, [pendingTemplate, onSelect]);

  const cancelReplace = useCallback(() => {
    setPendingTemplate(null);
  }, []);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setHighlightIndex((prev) => (prev < filteredTemplates.length - 1 ? prev + 1 : prev));
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setHighlightIndex((prev) => (prev > 0 ? prev - 1 : 0));
      } else if (e.key === 'Enter' && highlightIndex >= 0) {
        e.preventDefault();
        handleSelect(filteredTemplates[highlightIndex]);
      } else if (e.key === 'Escape') {
        setIsOpen(false);
      }
    },
    [filteredTemplates, highlightIndex, handleSelect]
  );

  return (
    <div className={cn('relative', className)}>
      <button
        type="button"
        aria-label="Template"
        aria-expanded={isOpen}
        className={cn(
          'inline-flex items-center gap-1 rounded-md px-2.5 py-1.5 text-sm',
          'hover:bg-accent hover:text-accent-foreground',
          'focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-1'
        )}
        onClick={() => setIsOpen(!isOpen)}
      >
        <LayoutTemplate className="h-4 w-4" />
        <span>Template</span>
        <ChevronDown className="h-3 w-3" />
      </button>

      {isOpen && (
        <div className="absolute bottom-full right-0 z-50 mb-1 w-80 rounded-md border border-border bg-popover p-2 shadow-lg">
          {/* Search input */}
          <div className="relative mb-2">
            <Search className="absolute left-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
            <input
              type="text"
              placeholder="Search templates..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setHighlightIndex(-1);
              }}
              onKeyDown={handleKeyDown}
              className="w-full rounded-md border border-input bg-transparent py-1.5 pl-7 pr-2 text-sm placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-ring"
            />
          </div>

          {/* Template list */}
          {filteredTemplates.length === 0 ? (
            <div className="py-4 text-center text-sm text-muted-foreground">
              No templates available
            </div>
          ) : (
            <ul className="max-h-48 space-y-0.5 overflow-auto">
              {filteredTemplates.map((template, i) => (
                <li key={template.id} data-highlighted={i === highlightIndex ? true : undefined}>
                  <button
                    type="button"
                    aria-pressed={i === highlightIndex}
                    tabIndex={-1}
                    className={cn(
                      'w-full text-left cursor-pointer rounded-md px-2 py-1.5 text-sm',
                      'hover:bg-accent hover:text-accent-foreground',
                      i === highlightIndex && 'bg-accent text-accent-foreground'
                    )}
                    onFocus={() => setHighlightIndex(i)}
                    onClick={() => handleSelect(template)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault();
                        handleSelect(template);
                      }
                    }}
                  >
                    <div className="flex items-center justify-between">
                      <span className="font-medium">{template.name}</span>
                      <span className="rounded-full bg-secondary px-1.5 py-0.5 text-[10px]">
                        {template.category}
                      </span>
                    </div>
                    <div className="mt-0.5 text-xs text-muted-foreground line-clamp-1">
                      {template.body.replaceAll(/<[^<>]*>/g, '').slice(0, 60)}...
                    </div>
                    {/* Merge variables */}
                    {template.variables.length > 0 && (
                      <div className="mt-1 flex flex-wrap gap-1">
                        {template.variables.map((v) => (
                          <span
                            key={v}
                            className="rounded bg-primary/10 px-1 py-0.5 text-[10px] font-mono text-primary"
                          >
                            {`{{${v}}}`}
                          </span>
                        ))}
                      </div>
                    )}
                  </button>
                </li>
              ))}
            </ul>
          )}

          {/* Confirmation dialog */}
          {pendingTemplate && (
            <div className="mt-2 rounded-md border border-warning bg-warning/10 p-2">
              <p className="text-sm">
                Replace existing content with template &ldquo;{pendingTemplate.name}&rdquo;?
              </p>
              <div className="mt-2 flex gap-2">
                <button
                  type="button"
                  className="rounded-md bg-primary px-2 py-1 text-xs text-primary-foreground hover:bg-primary/90 focus:outline-none focus:ring-2 focus:ring-ring"
                  onClick={confirmReplace}
                >
                  Replace
                </button>
                <button
                  type="button"
                  className="rounded-md border border-input px-2 py-1 text-xs hover:bg-accent focus:outline-none focus:ring-2 focus:ring-ring"
                  onClick={cancelReplace}
                >
                  Cancel
                </button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { Card, Progress } from '@intelliflow/ui';
import { useTimezoneContext } from '@/providers/TimezoneProvider';
import { PageHeader } from '@/components/shared';
import { getScoreColor, getProgressColor } from './quality-report-utils';

interface CoverageDetails {
  lines: number;
  branches: number;
  functions: number;
  statements: number;
  testsTotal?: number;
  testsPassed?: number;
  testsFailed?: number;
  thresholdsMet?: boolean;
  statusMessage?: string;
  failingTests?: Array<{ file: string; test: string }>;
}

interface QualityReport {
  id: string;
  name: string;
  type: string;
  status: string;
  score?: number;
  generatedAt: string;
  source: string;
  details?: CoverageDetails;
  isPlaceholder?: boolean;
  placeholderReason?: string;
}

const metrics: { key: keyof CoverageDetails; label: string; threshold: number }[] = [
  { key: 'statements', label: 'Statements', threshold: 90 },
  { key: 'branches', label: 'Branches', threshold: 80 },
  { key: 'functions', label: 'Functions', threshold: 90 },
  { key: 'lines', label: 'Lines', threshold: 90 },
];

function formatNumber(n: number): string {
  return n.toLocaleString('en-GB');
}

export default function CoverageReportView() {
  const { timezone } = useTimezoneContext();
  const [report, setReport] = useState<QualityReport | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchReport() {
      try {
        const response = await fetch('/api/quality-reports?action=detail&id=coverage');
        const result = await response.json();
        if (result.success) {
          setReport(result.data);
        } else {
          setError('Failed to load report data');
        }
      } catch {
        setError('Failed to load coverage report');
      } finally {
        setLoading(false);
      }
    }
    fetchReport();
  }, []);

  const details = report?.details;
  const isPlaceholder = report?.isPlaceholder || report?.source === 'placeholder';

  return (
    <>
      <PageHeader
        breadcrumbs={[
          { label: 'Dashboard', href: '/dashboard' },
          { label: 'Governance', href: '/governance' },
          { label: 'Quality Reports', href: '/governance/quality-reports' },
          { label: 'Test Coverage' },
        ]}
        title="Test Coverage Report"
        description="Test coverage by metric with threshold indicators"
        className="mb-8"
      />

      {loading && (
        <div className="text-center py-16 text-muted-foreground">
          <span className="material-symbols-outlined text-5xl mb-4 animate-spin">
            progress_activity
          </span>
          <p className="text-lg">Loading report...</p>
        </div>
      )}

      {!loading && error && (
        <Card className="p-12 text-center">
          <span className="material-symbols-outlined text-5xl text-red-500 mb-4">error</span>
          <h3 className="text-lg font-semibold text-foreground mb-2">Failed to Load Report</h3>
          <p className="text-muted-foreground">{error}</p>
        </Card>
      )}

      {!loading && !error && isPlaceholder && (
        <Card className="p-12 text-center">
          <span className="material-symbols-outlined text-5xl text-muted-foreground mb-4">
            info
          </span>
          <h3 className="text-lg font-semibold text-foreground mb-2">
            No Coverage Report Available
          </h3>
          <p className="text-muted-foreground">
            {report?.placeholderReason ||
              'No coverage report has been generated yet. Run tests with coverage to populate this page.'}
          </p>
        </Card>
      )}

      {!loading && !error && report && !isPlaceholder && details && (
        <>
          {/* Metric Cards */}
          {}
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4 mb-6">
            {metrics.map(({ key, label, threshold }) => {
              const value = details[key] as number;
              const passing = value >= threshold;

              return (
                <Card key={key} className="p-4" role="region" aria-label={`${label} coverage`}>
                  <div className="flex items-center justify-between mb-3">
                    <h3 className="font-medium text-foreground">{label}</h3>
                    <span
                      className={`px-2 py-0.5 rounded-full text-xs font-medium ${
                        passing
                          ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400'
                          : 'bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400'
                      }`}
                    >
                      {passing ? 'Pass' : 'Fail'}
                    </span>
                  </div>
                  <div
                    data-score-card
                    className={`text-3xl font-bold mb-2 ${getScoreColor(value)}`}
                  >
                    {value}%
                  </div>
                  <Progress
                    value={value}
                    className={`h-2 ${getProgressColor(value)}`}
                    aria-label={`${label} coverage: ${value}%`}
                  />
                  <p className="text-xs text-muted-foreground mt-2">Threshold: &ge;{threshold}%</p>
                </Card>
              );
            })}
          </div>

          {/* Test Metadata */}
          {details.testsTotal !== undefined && (
            <Card className="p-4 mb-6" role="region" aria-label="Test run metadata">
              <h3 className="font-semibold text-foreground mb-3">Test Run Summary</h3>
              <div className="grid gap-4 md:grid-cols-3">
                <div className="text-center">
                  <p className="text-2xl font-bold text-foreground">
                    {formatNumber(details.testsTotal)}
                  </p>
                  <p className="text-sm text-muted-foreground">Total Tests</p>
                </div>
                <div className="text-center">
                  <p className="text-2xl font-bold text-emerald-500">
                    {formatNumber(details.testsPassed ?? 0)}
                  </p>
                  <p className="text-sm text-muted-foreground">Passed</p>
                </div>
                <div className="text-center">
                  <p
                    className={`text-2xl font-bold ${(details.testsFailed ?? 0) > 0 ? 'text-red-500' : 'text-foreground'}`}
                  >
                    {formatNumber(details.testsFailed ?? 0)}
                  </p>
                  <p className="text-sm text-muted-foreground">Failed</p>
                </div>
              </div>
            </Card>
          )}

          {/* Failing Tests List */}
          {details.failingTests && details.failingTests.length > 0 && (
            <Card className="p-4 mb-6" role="region" aria-label="Failing tests">
              <h3 className="font-semibold text-foreground mb-3">Failing Tests</h3>
              <div className="space-y-2">
                {details.failingTests.map((ft, i) => (
                  <div key={i} className="flex items-start gap-2 text-sm">
                    <span className="material-symbols-outlined text-base text-red-500 mt-0.5">
                      close
                    </span>
                    <div>
                      <p className="font-medium text-foreground">{ft.file}</p>
                      <p className="text-muted-foreground">{ft.test}</p>
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}
          {}

          {/* Metadata */}
          <Card className="p-4">
            <div className="flex items-center gap-3 text-sm text-muted-foreground">
              <span className="material-symbols-outlined text-base">schedule</span>
              <span>
                Generated:{' '}
                {new Date(report.generatedAt).toLocaleDateString('en-GB', {
                  month: 'short',
                  day: 'numeric',
                  year: 'numeric',
                  hour: '2-digit',
                  minute: '2-digit',
                  timeZone: timezone,
                })}
              </span>
              {report.source === 'ci' && (
                <span className="px-2 py-0.5 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 text-xs rounded-full font-medium">
                  CI Generated
                </span>
              )}
            </div>
          </Card>
        </>
      )}
    </>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { Card, Progress, Button } from '@intelliflow/ui';
import { useTimezoneContext } from '@/providers/TimezoneProvider';
import { PageHeader } from '@/components/shared';
import { getScoreColor, getScoreBgColor, getProgressColor } from './quality-report-utils';

// ============================================================================
// Types
// ============================================================================

interface LighthouseVitals {
  fcp?: number | null;
  lcp?: number | null;
  tbt?: number | null;
  cls?: number | null;
  tti?: number | null;
  si?: number | null;
  serverResponse?: number | null;
  jsBytes?: number | null;
  totalBytes?: number | null;
  url?: string | null;
}

interface LighthouseDetails {
  performance: number;
  accessibility: number;
  bestPractices: number;
  seo: number;
  vitals?: LighthouseVitals;
}

interface QualityReport {
  id: string;
  name: string;
  type: string;
  status: string;
  score?: number;
  generatedAt: string;
  source: string;
  htmlPath?: string;
  details?: LighthouseDetails;
  isPlaceholder?: boolean;
  placeholderReason?: string;
}

const SCORE_THRESHOLD = 90;

// ============================================================================
// Targets (from lighthouserc.js)
// ============================================================================

const VITAL_TARGETS = {
  fcp: { max: 1000, unit: 'ms', label: 'First Contentful Paint' },
  lcp: { max: 2500, unit: 'ms', label: 'Largest Contentful Paint' },
  tbt: { max: 300, unit: 'ms', label: 'Total Blocking Time' },
  cls: { max: 0.1, unit: '', label: 'Cumulative Layout Shift' },
  tti: { max: 1000, unit: 'ms', label: 'Time to Interactive' },
  si: { max: 3000, unit: 'ms', label: 'Speed Index' },
  serverResponse: { max: 200, unit: 'ms', label: 'Server Response (TTFB)' },
} as const;

const RESOURCE_TARGETS = {
  jsBytes: { max: 307200, label: 'JavaScript', unit: 'KB' }, // 300 KB
  totalBytes: { max: 1024000, label: 'Total Page Weight', unit: 'KB' }, // 1 MB
} as const;

const categories: { key: keyof Omit<LighthouseDetails, 'vitals'>; label: string }[] = [
  { key: 'performance', label: 'Performance' },
  { key: 'accessibility', label: 'Accessibility' },
  { key: 'bestPractices', label: 'Best Practices' },
  { key: 'seo', label: 'SEO' },
];

// ============================================================================
// Sub-components
// ============================================================================

function PassFailPill({ passing }: { passing: boolean }) {
  return (
    <span
      className={`px-2 py-0.5 rounded-full text-xs font-medium ${
        passing
          ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400'
          : 'bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400'
      }`}
    >
      {passing ? 'Pass' : 'Fail'}
    </span>
  );
}

function formatVital(value: number, unit: string): string {
  if (unit === 'ms') return Math.round(value) + 'ms';
  if (unit === '') return value.toFixed(4);
  return value.toString();
}

function WebVitalsSection({ vitals }: { vitals: LighthouseVitals }) {
  const rows = (Object.keys(VITAL_TARGETS) as (keyof typeof VITAL_TARGETS)[])
    .map((key) => {
      const value = vitals[key];
      const target = VITAL_TARGETS[key];
      if (value == null) return null;
      const passing = value <= target.max;
      return { key, label: target.label, value, target, passing };
    })
    .filter((r): r is NonNullable<typeof r> => r !== null);

  if (rows.length === 0) return null;

  return (
    <Card className="p-4 mb-6" role="region" aria-label="Core Web Vitals">
      <h3 className="font-semibold text-foreground mb-4">Core Web Vitals</h3>
      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-border">
              <th className="text-left py-2 pr-3 font-medium text-muted-foreground">Metric</th>
              <th className="text-right py-2 pr-3 font-medium text-muted-foreground">Actual</th>
              <th className="text-right py-2 pr-3 font-medium text-muted-foreground">Target</th>
              <th className="text-center py-2 font-medium text-muted-foreground">Status</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r) => (
              <tr key={r.key} className="border-b border-border/30">
                <td className="py-2.5 pr-3 text-foreground">{r.label}</td>
                <td
                  className={`py-2.5 pr-3 text-right font-mono text-xs font-medium ${r.passing ? 'text-emerald-500' : 'text-red-500'}`}
                >
                  {formatVital(r.value, r.target.unit)}
                </td>
                <td className="py-2.5 pr-3 text-right text-muted-foreground font-mono text-xs">
                  &lt;{formatVital(r.target.max, r.target.unit)}
                </td>
                <td className="py-2.5 text-center">
                  <PassFailPill passing={r.passing} />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </Card>
  );
}

function ResourceBudgetsSection({ vitals }: { vitals: LighthouseVitals }) {
  const rows = (Object.keys(RESOURCE_TARGETS) as (keyof typeof RESOURCE_TARGETS)[])
    .map((key) => {
      const value = vitals[key];
      const target = RESOURCE_TARGETS[key];
      if (value == null) return null;
      const passing = value <= target.max;
      return {
        key,
        label: target.label,
        value,
        max: target.max,
        passing,
        kb: (value / 1024).toFixed(0),
        maxKb: (target.max / 1024).toFixed(0),
        pct: Math.min(100, Math.round((value / target.max) * 100)),
      };
    })
    .filter((r): r is NonNullable<typeof r> => r !== null);

  if (rows.length === 0) return null;

  return (
    <Card className="p-4 mb-6" role="region" aria-label="Resource budgets">
      <h3 className="font-semibold text-foreground mb-4">Resource Budgets</h3>
      <div className="space-y-3">
        {rows.map((r) => (
          <div key={r.key}>
            <div className="flex items-center justify-between mb-1.5">
              <div className="flex items-center gap-2">
                <span className="text-sm text-foreground">{r.label}</span>
                <PassFailPill passing={r.passing} />
              </div>
              <div className="text-xs font-mono text-muted-foreground">
                <span className={r.passing ? 'text-emerald-500' : 'text-red-500'}>{r.kb} KB</span>
                {' / '}
                <span>{r.maxKb} KB budget</span>
              </div>
            </div>
            <Progress
              value={r.pct}
              className={`h-2 ${r.passing ? '[&>div]:bg-emerald-500' : '[&>div]:bg-red-500'}`}
              aria-label={`${r.label}: ${r.kb} KB of ${r.maxKb} KB budget`}
            />
          </div>
        ))}
      </div>
    </Card>
  );
}

function FullReportSection({ htmlPath }: { htmlPath?: string }) {
  const [showEmbed, setShowEmbed] = useState(false);

