'use client';

import { useEffect, useState } from 'react';
import {
  getStoredDpaSignature,
  hasSigned,
  recordDpaSignature,
} from '@/lib/legal/signature-handler.client';

interface DpaSignaturePanelProps {
  currentVersion: string;
  downloadPath: string;
}

type PanelState = 'loading' | 'pending' | 'signed' | 'updated';

export function DpaSignaturePanel({ currentVersion, downloadPath }: DpaSignaturePanelProps) {
  const [state, setState] = useState<PanelState>('loading');
  const [signatoryName, setSignatoryName] = useState('');
  const [checked, setChecked] = useState(false);

  useEffect(() => {
    if (hasSigned(currentVersion)) {
      setState('signed');
    } else {
      const stored = getStoredDpaSignature();
      if (stored) {
        setState('updated');
      } else {
        setState('pending');
      }
    }
  }, [currentVersion]);

  function handleExecute() {
    if (!signatoryName.trim() || !checked) return;
    recordDpaSignature(currentVersion, signatoryName.trim());
    setState('signed');
  }

  // SSR-safe: return null during loading and signed states (NF-002)
  if (state === 'loading' || state === 'signed') {
    return null;
  }

  const disclaimer = (
    <p className="mt-2 text-xs text-slate-500 dark:text-slate-400">
      This acknowledgment is stored locally in your browser. For a countersigned DPA for enterprise
      records, contact{' '}
      <a href="mailto:legal@intelliflow-crm.com" className="underline">
        legal@intelliflow-crm.com
      </a>
      .
    </p>
  );

  const inputs = (
    <div className="flex flex-col gap-2 sm:flex-row sm:items-end sm:gap-3">
      <div className="flex flex-col gap-1">
        <label
          htmlFor="dpa-signatory-name"
          className="text-xs font-medium text-slate-700 dark:text-slate-300"
        >
          Full name
        </label>
        <input
          id="dpa-signatory-name"
          type="text"
          required
          placeholder="Your full legal name"
          value={signatoryName}
          onChange={(e) => setSignatoryName(e.target.value)}
          className="rounded-lg border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 placeholder-slate-400 focus:border-[#137fec] focus:outline-none focus:ring-2 focus:ring-[#137fec]/30 dark:border-slate-600 dark:bg-slate-800 dark:text-slate-100"
        />
      </div>
      {/* TODO: Replace placeholder PDF with legal-reviewed DPA template before production deploy */}
      <a
        href={downloadPath}
        download
        className="inline-flex items-center gap-1 rounded-lg border border-[#137fec] px-3 py-2 text-sm font-medium text-[#137fec] transition-colors hover:bg-[#137fec]/10"
      >
        Download DPA Template
      </a>
    </div>
  );

  const checkboxAndButton = (
    <div className="flex items-center gap-3 flex-wrap">
      <label className="flex cursor-pointer items-center gap-2 text-sm text-slate-700 dark:text-slate-300">
        <input
          type="checkbox"
          checked={checked}
          onChange={(e) => setChecked(e.target.checked)}
          className="h-4 w-4 rounded border-slate-300 accent-[#137fec]"
        />
        I have read and I agree to the Data Processing Addendum
      </label>
      <button
        onClick={handleExecute}
        disabled={!signatoryName.trim() || !checked}
        className="rounded-lg bg-[#137fec] px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-[#0d6ecc] disabled:cursor-not-allowed disabled:opacity-50"
      >
        Execute DPA
      </button>
    </div>
  );

  if (state === 'updated') {
    return (
      <div
        role="status"
        className="fixed bottom-0 left-0 right-0 z-50 border-t border-amber-200 bg-amber-50 px-4 py-4 shadow-lg dark:border-amber-800 dark:bg-amber-950"
      >
        <div className="container mx-auto max-w-6xl">
          <div className="flex items-start gap-4">
            <span
              className="material-symbols-outlined mt-0.5 text-xl text-amber-600 dark:text-amber-400"
              aria-hidden="true"
            >
              info
            </span>
            <div className="flex-1">
              <p className="text-sm font-semibold text-amber-900 dark:text-amber-100">
                DPA updated ÔÇö Re-acknowledge required ({currentVersion})
              </p>
              <p className="mt-1 text-sm text-amber-800 dark:text-amber-200">
                Our Data Processing Addendum has been updated. Please review the changes and
                re-acknowledge to confirm your continued agreement.
              </p>
              <div className="mt-3">
                {inputs}
                <div className="mt-3">{checkboxAndButton}</div>
                {disclaimer}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // state === 'pending'
  return (
    <div
      role="status"
      className="fixed bottom-0 left-0 right-0 z-50 border-t border-[#137fec]/20 bg-white px-4 py-4 shadow-lg dark:border-[#137fec]/30 dark:bg-[#162231]"
    >
      <div className="container mx-auto max-w-6xl">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:gap-6">
          <div className="flex-1">
            <p className="text-sm font-semibold text-slate-800 dark:text-slate-100">
              Data Processing Addendum ({currentVersion})
            </p>
            <p className="mt-0.5 text-sm text-slate-600 dark:text-slate-300">
              As a data controller using IntelliFlow CRM, please execute this DPA to formalise our
              GDPR Article 28 data processor relationship.
            </p>
          </div>
          <div className="flex flex-col gap-3">
            {inputs}
            {checkboxAndButton}
            {disclaimer}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useCallback, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@intelliflow/ui';

import {
  getTypeConfig,
  getPriorityConfig,
  formatRelativeTime,
  getProactiveAlertCategory,
} from './notification-utils';

/** Accept tRPC-inferred notification type (Date fields from superjson) */
interface NotificationItemProps {
  notification: {
    id: string;
    type: string;
    priority: string;
    title: string;
    body: string;
    isRead: boolean;
    createdAt: string | Date;
    actionUrl?: string | null;
    actionLabel?: string | null;
  };
  onMarkAsRead: (id: string) => void;
  onDismiss: (id: string) => void;
}

export const NotificationItem = React.memo(function NotificationItem({
  notification,
  onMarkAsRead,
  onDismiss,
}: Readonly<NotificationItemProps>) {
  const router = useRouter();
  const typeConfig = getTypeConfig(notification.type);
  const priorityConfig = getPriorityConfig(notification.priority);
  const proactiveCategory = getProactiveAlertCategory(notification.type);

  // Optimistic local state ÔÇö immediately reflects "read" on click
  // without waiting for the mutation round-trip + cache refetch.
  // Resets when server state catches up (notification.isRead becomes true).
  const [optimisticRead, setOptimisticRead] = useState(false);
  const isAiType = notification.type.startsWith('ai_');
  const isUnread = !notification.isRead && !optimisticRead;
  const actionLink = notification.actionUrl;
  const isClickable = isUnread || !!actionLink;
  const unreadOrReadClass = isUnread
    ? 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'
    : 'bg-slate-50/50 dark:bg-slate-800/50 border-transparent hover:bg-white dark:hover:bg-slate-800 hover:border-slate-200 dark:hover:border-slate-700';
  const containerClass = isAiType
    ? 'bg-indigo-50/40 dark:bg-indigo-900/10 border-indigo-100 dark:border-indigo-800/30 hover:border-indigo-200 dark:hover:border-indigo-700/50'
    : unreadOrReadClass;

  const activateItem = useCallback(() => {
    if (isUnread) {
      setOptimisticRead(true);
      onMarkAsRead(notification.id);
    }
    if (actionLink) {
      router.push(actionLink);
    }
  }, [isUnread, actionLink, notification.id, onMarkAsRead, router]);

  const handleItemClick = useCallback(
    (e: React.MouseEvent) => {
      // Don't navigate if clicking on action buttons
      if ((e.target as HTMLElement).closest('button')) return;
      activateItem();
    },
    [activateItem]
  );

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        activateItem();
      }
    },
    [activateItem]
  );

  let divRole: 'link' | 'button' | undefined;
  if (actionLink) divRole = 'link';
  else if (isClickable) divRole = 'button';

  return (
    <div
      onClick={handleItemClick}
      onKeyDown={handleKeyDown}
      role={divRole}
      tabIndex={isClickable ? 0 : undefined}
      className={`group relative flex w-full items-start gap-4 rounded-xl p-4 shadow-sm border transition-all hover:shadow-md ${isClickable ? 'cursor-pointer' : ''} ${containerClass}`}
    >
      {/* Priority Indicator */}
      {priorityConfig && (
        <div
          className={`absolute left-0 top-3 bottom-3 w-1 ${priorityConfig.borderColor} rounded-r-lg`}
        />
      )}

      {/* Icon */}
      <div
        className={`ml-2 flex h-10 w-10 shrink-0 items-center justify-center rounded-full ${typeConfig.bgColor} ${typeConfig.iconColor} ring-1 ${typeConfig.ringColor}`}
      >
        <span className="material-symbols-outlined">{typeConfig.icon}</span>
      </div>

      {/* Content */}
      <div className="flex flex-1 flex-col gap-1">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <h3
              className={`text-sm ${isUnread ? 'font-bold' : 'font-medium'} text-slate-900 dark:text-white`}
            >
              {notification.title}
            </h3>
            {notification.priority === 'high' && priorityConfig && (
              <span
                className={`inline-flex items-center rounded-md px-2 py-1 text-xs font-medium ring-1 ring-inset ${priorityConfig.badgeBg} ${priorityConfig.badgeText} ${priorityConfig.badgeRing}`}
              >
                {priorityConfig.label}
              </span>
            )}
            {isUnread && <div className="h-2 w-2 rounded-full bg-primary" />}
          </div>
          <span className="text-xs font-medium text-slate-500 dark:text-slate-400">
            {formatRelativeTime(notification.createdAt)}
          </span>
        </div>
        <p
          className={`text-sm ${isUnread ? 'text-slate-700 dark:text-slate-300' : 'text-slate-600 dark:text-slate-400'} line-clamp-2 pr-12`}
        >
          {notification.body}
        </p>
        <div className="flex items-center gap-2 mt-1">
          <span
            className={`text-xs px-2 py-0.5 rounded-full ${typeConfig.bgColor} ${typeConfig.iconColor}`}
          >
            {typeConfig.group}
          </span>
          {proactiveCategory && (
            <span className="text-xs px-2 py-0.5 rounded-full bg-violet-50 dark:bg-violet-900/20 text-violet-600 dark:text-violet-400 flex items-center gap-1">
              <span className="material-symbols-outlined text-[11px]" aria-hidden="true">
                notifications_active
              </span>
              {proactiveCategory}
            </span>
          )}
          {actionLink && (
            <span className="text-xs text-primary flex items-center gap-1">
              View details <span className="material-symbols-outlined text-sm">arrow_forward</span>
            </span>
          )}
        </div>
      </div>

      {/* Actions ÔÇö visible on hover and focus-within */}
      <div
        className={`absolute right-4 top-4 flex items-center gap-1 opacity-0 group-hover:opacity-100 group-focus-within:opacity-100 transition-opacity ${isAiType ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'bg-white dark:bg-slate-800'} pl-2 backdrop-blur-sm`}
      >
        <TooltipProvider>
          {isUnread && (
            <Tooltip>
              <TooltipTrigger asChild>
                <button
                  onClick={() => {
                    setOptimisticRead(true);
                    onMarkAsRead(notification.id);
                  }}
                  aria-label="Mark as read"
                  className="flex h-8 w-8 items-center justify-center rounded-md text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 hover:text-primary"
                >
                  <span className="material-symbols-outlined text-[20px]">check_circle</span>
                </button>
              </TooltipTrigger>
              <TooltipContent>Mark as read</TooltipContent>
            </Tooltip>
          )}
          <Tooltip>
            <TooltipTrigger asChild>
              <button
                onClick={() => onDismiss(notification.id)}
                aria-label="Dismiss"
                className="flex h-8 w-8 items-center justify-center rounded-md text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 hover:text-red-500"
              >
                <span className="material-symbols-outlined text-[20px]">close</span>
              </button>
            </TooltipTrigger>
            <TooltipContent>Dismiss</TooltipContent>
          </Tooltip>
        </TooltipProvider>
      </div>
    </div>
  );
});

