'use client';

import * as React from 'react';
import { cn } from '@intelliflow/ui';
import { isAvatarImageSource, normalizeAvatarSource } from '@/lib/shared/avatar-utils';

export interface AppAvatarProps extends React.HTMLAttributes<HTMLDivElement> {
  name: string;
  src?: string | null;
  fallbackText?: string | null;
  alt?: string;
  maxInitials?: number;
  imageClassName?: string;
  fallbackClassName?: string;
}

function getInitials(name: string, maxInitials: number): string {
  const parts = name
    .split(' ')
    .map((part) => part.trim())
    .filter(Boolean);

  if (parts.length === 0) {
    return '?';
  }

  if (parts.length === 1) {
    return parts[0].slice(0, maxInitials).toUpperCase() || '?';
  }

  return parts
    .slice(0, maxInitials)
    .map((part) => part[0])
    .join('')
    .toUpperCase();
}

export function AppAvatar({
  name,
  src = null,
  fallbackText = null,
  alt,
  maxInitials = 2,
  className,
  imageClassName,
  fallbackClassName,
  ...props
}: Readonly<AppAvatarProps>) {
  const normalizedSrc = React.useMemo(() => normalizeAvatarSource(src), [src]);
  const initialImageSource = React.useMemo(() => {
    if (!normalizedSrc || !isAvatarImageSource(normalizedSrc)) {
      return null;
    }
    return normalizedSrc;
  }, [normalizedSrc]);

  const [hasImageError, setHasImageError] = React.useState(false);

  React.useEffect(() => {
    setHasImageError(false);
  }, [initialImageSource]);

  const imageSource = initialImageSource && !hasImageError ? initialImageSource : null;
  const showImage = Boolean(imageSource);

  const trimmedFallback = fallbackText?.trim() ?? '';
  const sourceFallback = normalizedSrc && !initialImageSource ? normalizedSrc : '';
  const initials = getInitials(name, maxInitials);
  const fallbackLabel = trimmedFallback || sourceFallback || initials;

  return (
    <span
      className={cn(
        'relative flex shrink-0 items-center justify-center overflow-hidden rounded-full',
        showImage
          ? 'bg-transparent'
          : 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-200',
        !showImage && fallbackClassName,
        className
      )}
      role="img"
      aria-label={alt ?? `Avatar for ${name}`}
      {...props}
    >
      {showImage ? (
        <img
          src={imageSource ?? undefined}
          alt={alt ?? name}
          className={cn('h-full w-full object-cover', imageClassName)}
          onError={() => {
            setHasImageError(true);
          }}
        />
      ) : null}
      {showImage ? null : <span className="font-semibold">{fallbackLabel}</span>}
    </span>
  );
}

'use client';

/**
 * Registration Form Component
 *
 * Reusable registration form with validation, password strength indicator,
 * and accessibility support.
 *
 * IMPLEMENTS: PG-016 (Sign Up page)
 *
 * Features:
 * - Full name, email, password, and confirm password fields
 * - Real-time password strength indicator
 * - Terms acceptance checkbox
 * - Client-side validation with error messages
 * - ARIA accessibility support
 */

import { useState, useCallback, useId, useEffect, useRef } from 'react';
import Link from 'next/link';
import { cn } from '@intelliflow/ui';
import { PasswordInput } from './password-input';
import {
  checkPasswordBreach,
  formatBreachCount,
  type BreachCheckResult,
} from '@/lib/shared/password-breach-check';

// ============================================
// Types
// ============================================

export interface RegistrationFormData {
  fullName: string;
  email: string;
  password: string;
  confirmPassword: string;
  acceptTerms: boolean;
}

export interface RegistrationFormErrors {
  fullName?: string;
  email?: string;
  password?: string;
  confirmPassword?: string;
  acceptTerms?: string;
}

export interface RegistrationFormProps {
  onSubmit: (data: RegistrationFormData) => Promise<void>;
  isLoading?: boolean;
  className?: string;
  initialEmail?: string;
}

// ============================================
// Password Strength Calculator
// ============================================

type PasswordStrength = 'weak' | 'fair' | 'good' | 'strong';

interface PasswordStrengthResult {
  strength: PasswordStrength;
  score: number;
  feedback: string[];
}

type PasswordCheck = { test: (p: string) => boolean; label: string };

const PASSWORD_CHECKS: PasswordCheck[] = [
  { test: (p) => p.length >= 8, label: 'At least 8 characters' },
  { test: (p) => p.length >= 12, label: '' }, // bonus point, no feedback label
  { test: (p) => /[a-z]/.test(p), label: 'Lowercase letter' },
  { test: (p) => /[A-Z]/.test(p), label: 'Uppercase letter' },
  { test: (p) => /\d/.test(p), label: 'Number' },
  { test: (p) => /[^a-zA-Z0-9]/.test(p), label: 'Special character' },
];

function scoreToStrength(score: number): PasswordStrength {
  if (score <= 2) return 'weak';
  if (score <= 3) return 'fair';
  if (score <= 5) return 'good';
  return 'strong';
}

function calculatePasswordStrength(password: string): PasswordStrengthResult {
  const feedback: string[] = [];
  let score = 0;

  for (const check of PASSWORD_CHECKS) {
    if (check.test(password)) {
      score += 1;
    } else if (check.label) {
      feedback.push(check.label);
    }
  }

  return { strength: scoreToStrength(score), score, feedback };
}

// ============================================
// Password Strength Indicator Component
// ============================================

interface PasswordStrengthIndicatorProps {
  password: string;
  className?: string;
}

function PasswordStrengthIndicator({
  password,
  className,
}: Readonly<PasswordStrengthIndicatorProps>) {
  if (!password) return null;

  const { strength, feedback } = calculatePasswordStrength(password);

  const strengthColors: Record<PasswordStrength, string> = {
    weak: 'bg-red-500',
    fair: 'bg-yellow-500',
    good: 'bg-blue-500',
    strong: 'bg-green-500',
  };

  const strengthLabels: Record<PasswordStrength, string> = {
    weak: 'Weak',
    fair: 'Fair',
    good: 'Good',
    strong: 'Strong',
  };

  const strengthWidths: Record<PasswordStrength, string> = {
    weak: 'w-1/4',
    fair: 'w-2/4',
    good: 'w-3/4',
    strong: 'w-full',
  };

  return (
    <div className={cn('mt-2', className)} aria-live="polite">
      <div className="flex items-center justify-between mb-1">
        <span className="text-xs text-slate-400">Password strength</span>
        <span
          className={cn('text-xs font-medium', {
            'text-red-400': strength === 'weak',
            'text-yellow-400': strength === 'fair',
            'text-blue-400': strength === 'good',
            'text-green-400': strength === 'strong',
          })}
        >
          {strengthLabels[strength]}
        </span>
      </div>
      <div className="h-1.5 bg-slate-700 rounded-full overflow-hidden">
        {}
        <span
          className={cn(
            'h-full rounded-full transition-all duration-300 block',
            strengthColors[strength],
            strengthWidths[strength]
          )}
          role="progressbar"
          aria-valuenow={Math.round((calculatePasswordStrength(password).score / 6) * 100)}
          aria-valuemin={0}
          aria-valuemax={100}
          aria-label={`Password strength: ${strengthLabels[strength]}`}
        />
      </div>
      {feedback.length > 0 && strength !== 'strong' && (
        <p className="text-xs text-slate-400 mt-1">Add: {feedback.slice(0, 2).join(', ')}</p>
      )}
    </div>
  );
}

// ============================================
// Field Validators
// ============================================

function validateFullName(value: string | boolean): string | undefined {
  if (!value || (typeof value === 'string' && value.trim().length < 2)) {
    return 'Full name is required (at least 2 characters)';
  }
  return undefined;
}

function validateEmail(value: string | boolean): string | undefined {
  if (!value || typeof value !== 'string') return 'Email is required';
  if (!/^[^\s@]+@[^\s@.]+\.[^\s@.]+$/.test(value)) {
    return 'Please enter a valid email address';
  }
  return undefined;
}

function validatePassword(value: string | boolean): string | undefined {
  if (!value || typeof value !== 'string') return 'Password is required';
  if (value.length < 8) return 'Password must be at least 8 characters';
  return undefined;
}

function validateConfirmPassword(value: string | boolean, password: string): string | undefined {
  if (!value || typeof value !== 'string') return 'Please confirm your password';
  if (value !== password) return 'Passwords do not match';
  return undefined;
}

function validateAcceptTerms(value: string | boolean): string | undefined {
  if (!value) return 'You must accept the terms and conditions';
  return undefined;
}

// ============================================
// Registration Form Component
// ============================================

export function RegistrationForm({
  onSubmit,
  isLoading = false,
  className,
  initialEmail = '',
}: Readonly<RegistrationFormProps>) {
  const formId = useId();

  // Form state
  const [formData, setFormData] = useState<RegistrationFormData>({
    fullName: '',
    email: initialEmail,
    password: '',
    confirmPassword: '',
    acceptTerms: false,
  });

  const [errors, setErrors] = useState<RegistrationFormErrors>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  // Breach check state (PG-016 security enhancement)
  const [breachWarning, setBreachWarning] = useState<string | null>(null);
  const [isCheckingBreach, setIsCheckingBreach] = useState(false);
  const breachCheckTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Cleanup breach check timeout on unmount
  useEffect(() => {
    return () => {
      if (breachCheckTimeoutRef.current) {
        clearTimeout(breachCheckTimeoutRef.current);
      }
    };
  }, []);

  // Debounced password breach check (500ms delay)
  const debouncedBreachCheck = useCallback((password: string) => {
    // Clear any pending check
    if (breachCheckTimeoutRef.current) {
      clearTimeout(breachCheckTimeoutRef.current);
    }

    // Skip check for short passwords
    if (!password || password.length < 8) {
      setBreachWarning(null);
      setIsCheckingBreach(false);
      return;
    }

    setIsCheckingBreach(true);

    breachCheckTimeoutRef.current = setTimeout(async () => {
      try {
        const result: BreachCheckResult = await checkPasswordBreach(password);

        if (result.breached && result.count) {
          setBreachWarning(
            `This password has been found in ${formatBreachCount(result.count)} data breaches. Consider using a different password.`
          );
        } else {
          setBreachWarning(null);
        }
      } catch (error) {
        // Non-blocking - don't show error to user
        console.warn('[RegistrationForm] Breach check failed:', error);
        setBreachWarning(null);
      } finally {
        setIsCheckingBreach(false);
      }
    }, 500);
  }, []);

  // Validation
  const validateField = useCallback(
    (name: keyof RegistrationFormData, value: string | boolean): string | undefined => {
      if (name === 'fullName') return validateFullName(value);
      if (name === 'email') return validateEmail(value);
      if (name === 'password') return validatePassword(value);
      if (name === 'confirmPassword') return validateConfirmPassword(value, formData.password);
      if (name === 'acceptTerms') return validateAcceptTerms(value);
      return undefined;
    },
    [formData.password]
  );

  const validateForm = useCallback((): boolean => {
    const newErrors: RegistrationFormErrors = {};
    let isValid = true;

    (Object.keys(formData) as Array<keyof RegistrationFormData>).forEach((field) => {
      const error = validateField(field, formData[field]);
      if (error) {
        newErrors[field] = error;
        isValid = false;
      }
    });

    setErrors(newErrors);
    return isValid;
  }, [formData, validateField]);

  // Event handlers
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const { name, value, type, checked } = e.target;
      const newValue = type === 'checkbox' ? checked : value;

      setFormData((prev) => ({ ...prev, [name]: newValue }));

      // Clear error on change if field was touched
      if (touched[name]) {
        const error = validateField(name as keyof RegistrationFormData, newValue);
        setErrors((prev) => ({ ...prev, [name]: error }));
      }
    },
    [touched, validateField]
  );

  const handlePasswordChange = useCallback(
    (value: string) => {
      setFormData((prev) => ({ ...prev, password: value }));
      if (touched.password) {
        const error = validateField('password', value);
        setErrors((prev) => ({ ...prev, password: error }));
      }
      // Also revalidate confirm password if it was touched
      if (touched.confirmPassword && formData.confirmPassword) {
        const confirmError =
          formData.confirmPassword === value ? undefined : 'Passwords do not match';
        setErrors((prev) => ({ ...prev, confirmPassword: confirmError }));
      }
      // Trigger debounced breach check
      debouncedBreachCheck(value);
    },
    [touched, validateField, formData.confirmPassword, debouncedBreachCheck]
  );

  const handleConfirmPasswordChange = useCallback(
    (value: string) => {
      setFormData((prev) => ({ ...prev, confirmPassword: value }));
      if (touched.confirmPassword) {
        const error = value === formData.password ? undefined : 'Passwords do not match';
        setErrors((prev) => ({ ...prev, confirmPassword: error }));
      }
    },
    [touched, formData.password]
  );

  const handleBlur = useCallback(
    (e: React.FocusEvent<HTMLInputElement>) => {
      const { name, value, type, checked } = e.target;
      const fieldValue = type === 'checkbox' ? checked : value;

      setTouched((prev) => ({ ...prev, [name]: true }));
      const error = validateField(name as keyof RegistrationFormData, fieldValue);
      setErrors((prev) => ({ ...prev, [name]: error }));
    },
    [validateField]
  );

  const handleSubmit = useCallback(
    async (e: React.SyntheticEvent) => {
      e.preventDefault();

      // Mark all fields as touched
      setTouched({
        fullName: true,
        email: true,
        password: true,
        confirmPassword: true,
        acceptTerms: true,
      });

      if (!validateForm()) {
        return;
      }

      await onSubmit(formData);
    },
    [formData, validateForm, onSubmit]
  );

  return (
    <form
      onSubmit={handleSubmit}
      className={cn('space-y-5', className)}
      noValidate
      aria-label="Registration form"
    >
      {/* Full Name Field */}
      <div>
        <label
          htmlFor={`${formId}-fullName`}
          className="block text-sm font-medium text-slate-200 mb-2"
        >
          Full name
        </label>
        <input
          id={`${formId}-fullName`}
          name="fullName"
          type="text"
          autoComplete="name"
          value={formData.fullName}
          onChange={handleChange}
          onBlur={handleBlur}
          disabled={isLoading}
          placeholder="Enter your full name"
          aria-invalid={!!errors.fullName}
          aria-describedby={errors.fullName ? `${formId}-fullName-error` : undefined}
          className={cn(
            'w-full px-4 py-3 rounded-lg border bg-slate-800/50 text-white placeholder-slate-400',
            'focus:outline-none focus:ring-2 focus:ring-[#137fec]/50 focus:border-primary',
            'transition-colors disabled:opacity-50 disabled:cursor-not-allowed',
            errors.fullName
              ? 'border-red-500/50 focus:border-red-500 focus:ring-red-500/50'
              : 'border-slate-600/50'
          )}
        />
        {errors.fullName && (
          <p
            id={`${formId}-fullName-error`}
            role="alert"
            className="mt-1.5 text-sm text-red-400 flex items-center gap-1.5"
          >
            <span className="material-symbols-outlined text-base" aria-hidden="true">
              error
            </span>
            {errors.fullName}
          </p>
        )}
      </div>

      {/* Email Field */}
      <div>
        <label
          htmlFor={`${formId}-email`}
          className="block text-sm font-medium text-slate-200 mb-2"
        >
          Email address
        </label>
        <input
          id={`${formId}-email`}
          name="email"
          type="email"
          autoComplete="email"
          value={formData.email}
          onChange={handleChange}
          onBlur={handleBlur}
          disabled={isLoading}
          placeholder="you@example.com"
          aria-invalid={!!errors.email}
          aria-describedby={errors.email ? `${formId}-email-error` : undefined}
          className={cn(
            'w-full px-4 py-3 rounded-lg border bg-slate-800/50 text-white placeholder-slate-400',
            'focus:outline-none focus:ring-2 focus:ring-[#137fec]/50 focus:border-primary',
            'transition-colors disabled:opacity-50 disabled:cursor-not-allowed',
            errors.email
              ? 'border-red-500/50 focus:border-red-500 focus:ring-red-500/50'
              : 'border-slate-600/50'
          )}
        />
        {errors.email && (
          <p
            id={`${formId}-email-error`}
            role="alert"
            className="mt-1.5 text-sm text-red-400 flex items-center gap-1.5"
          >
            <span className="material-symbols-outlined text-base" aria-hidden="true">
              error
            </span>
            {errors.email}
          </p>
        )}
      </div>

      {/* Password Field */}
      <div>
        <PasswordInput
          id={`${formId}-password`}
          label="Password"
          value={formData.password}
          onChange={handlePasswordChange}
          onBlur={() => {
            setTouched((prev) => ({ ...prev, password: true }));
            const error = validateField('password', formData.password);
            setErrors((prev) => ({ ...prev, password: error }));
          }}
          error={errors.password}
          disabled={isLoading}
          autoComplete="new-password"
          placeholder="Create a password"
        />
        <PasswordStrengthIndicator password={formData.password} />

        {/* Breach Warning (PG-016 security) */}
        {isCheckingBreach && (
          <div className="mt-2 flex items-center gap-2 text-xs text-slate-400">
            <span className="material-symbols-outlined animate-spin text-sm" aria-hidden="true">
              progress_activity
            </span>{' '}
            Checking password security...
          </div>
        )}
        {breachWarning && !isCheckingBreach && (
          <div
            className="mt-2 p-2 rounded bg-amber-500/10 border border-amber-500/30 flex items-start gap-2"
            role="alert"
            aria-live="polite"
          >
            <span
              className="material-symbols-outlined text-amber-500 text-base flex-shrink-0 mt-0.5"
              aria-hidden="true"
            >
              warning
            </span>
            <p className="text-xs text-amber-400">{breachWarning}</p>
          </div>
        )}
      </div>

      {/* Confirm Password Field */}
      <div>
        <PasswordInput
          id={`${formId}-confirmPassword`}
          label="Confirm password"
          value={formData.confirmPassword}
          onChange={handleConfirmPasswordChange}
          onBlur={() => {
            setTouched((prev) => ({ ...prev, confirmPassword: true }));
            const error =
              formData.confirmPassword === formData.password ? undefined : 'Passwords do not match';
            setErrors((prev) => ({ ...prev, confirmPassword: error }));
          }}
          error={errors.confirmPassword}
          disabled={isLoading}
          autoComplete="new-password"
          placeholder="Confirm your password"
        />
      </div>

      {/* Terms Checkbox */}
      <div className="flex items-start gap-3">
        <input
          id={`${formId}-acceptTerms`}
          name="acceptTerms"
          type="checkbox"
          checked={formData.acceptTerms}
          onChange={handleChange}
          onBlur={handleBlur}
          disabled={isLoading}
          aria-invalid={!!errors.acceptTerms}
          aria-describedby={errors.acceptTerms ? `${formId}-acceptTerms-error` : undefined}
          className={cn(
            'mt-0.5 h-4 w-4 rounded border-slate-600 bg-slate-800/50',
            'text-primary focus:ring-[#137fec]/50 focus:ring-offset-0',
            'disabled:opacity-50 disabled:cursor-not-allowed'
          )}
        />
        <div className="flex-1">
          <label htmlFor={`${formId}-acceptTerms`} className="text-sm text-slate-300">
            I agree to the{' '}
            <Link
              href="/terms"
              className="text-primary hover:text-primary/80 underline"
              target="_blank"
              rel="noopener noreferrer"
            >
              Terms of Service
            </Link>{' '}
            and{' '}
            <Link
              href="/privacy"
              className="text-primary hover:text-primary/80 underline"
              target="_blank"
              rel="noopener noreferrer"
            >
              Privacy Policy
            </Link>
          </label>
          {errors.acceptTerms && (
            <p
              id={`${formId}-acceptTerms-error`}
              role="alert"
              className="mt-1 text-sm text-red-400 flex items-center gap-1.5"
            >
              <span className="material-symbols-outlined text-base" aria-hidden="true">
                error
              </span>
              {errors.acceptTerms}
            </p>
          )}
        </div>
      </div>

      {/* Submit Button */}
      <button
        type="submit"
        disabled={isLoading}
        className={cn(
          'w-full py-3 px-4 rounded-lg font-semibold text-white',
          'bg-[#137fec] hover:bg-[#137fec]/90',
          'focus:outline-none focus:ring-2 focus:ring-[#137fec]/50 focus:ring-offset-2 focus:ring-offset-slate-900',
          'transition-all disabled:opacity-50 disabled:cursor-not-allowed',
          'flex items-center justify-center gap-2'
        )}
      >
        {isLoading ? (
          <>
            <span className="material-symbols-outlined animate-spin text-xl" aria-hidden="true">
              progress_activity
            </span>{' '}
            Creating account...
          </>
        ) : (
          'Create account'
        )}
      </button>
    </form>
  );
}

'use client';

/**
 * VariablePicker
 *
 * Free-text input + adjacent "{ } Insert variable" Popover. The popover
 * lists the variables available at run time (derived from a workflow's
 * trigger entity) and inserts the chosen `{{path}}` token at the
 * input's cursor position. Useful in any workflow free-text field ÔÇö
 * notification body, task title, instructions, etc.
 *
 * Inputs are controlled (`value` / `onChange`) so the parent owns the
 * canonical state. The popover is keyboard-accessible and uses the
 * shadcn `Popover` primitive from `@intelliflow/ui`.
 */

import { useRef, useState } from 'react';
import { Braces } from 'lucide-react';
import { Button, Input, Popover, PopoverContent, PopoverTrigger } from '@intelliflow/ui';

export interface VariableSuggestion {
  /** Full token path, e.g. `trigger.lead.name`. Inserted as `{{trigger.lead.name}}`. */
  path: string;
  /** Short label shown to the user (defaults to the path). */
  label?: string;
  /** Optional helper text shown below the label. */
  description?: string;
}

export interface VariablePickerProps {
  value: string;
  onChange: (next: string) => void;
  /** Variables the workflow makes available at run time. */
  variables: VariableSuggestion[];
  placeholder?: string;
  /** Render as <textarea> instead of <input> for multi-line bodies. */
  multiline?: boolean;
  ariaLabel?: string;
  /** Tailwind class for the input/textarea */
  className?: string;
}

export function VariablePicker({
  value,
  onChange,
  variables,
  placeholder,
  multiline = false,
  ariaLabel,
  className,
}: VariablePickerProps) {
  const inputRef = useRef<HTMLInputElement | HTMLTextAreaElement | null>(null);
  const [open, setOpen] = useState(false);

  const insertToken = (path: string) => {
    const token = `{{${path}}}`;
    const el = inputRef.current;
    if (!el) {
      onChange(value + token);
      setOpen(false);
      return;
    }
    const start = el.selectionStart ?? value.length;
    const end = el.selectionEnd ?? value.length;
    const next = value.slice(0, start) + token + value.slice(end);
    onChange(next);
    setOpen(false);
    // Restore caret position AFTER React re-renders the controlled value.
    requestAnimationFrame(() => {
      if (!inputRef.current) return;
      const caret = start + token.length;
      inputRef.current.focus();
      inputRef.current.setSelectionRange(caret, caret);
    });
  };

  return (
    <div className={multiline ? 'flex flex-col gap-1' : 'flex gap-2 items-start'}>
      {multiline ? (
        <textarea
          ref={(el) => {
            inputRef.current = el;
          }}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          aria-label={ariaLabel}
          placeholder={placeholder}
          className={
            className ??
            'w-full rounded-md border border-input px-3 py-2 text-sm min-h-[80px] resize-y'
          }
        />
      ) : (
        <Input
          ref={(el) => {
            inputRef.current = el;
          }}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          aria-label={ariaLabel}
          placeholder={placeholder}
          className={className}
        />
      )}
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild>
          <Button
            type="button"
            variant="outline"
            size="sm"
            aria-label="Insert variable"
            className={multiline ? 'self-end' : ''}
          >
            <Braces className="h-4 w-4" aria-hidden="true" />
            <span className="ml-1.5 hidden sm:inline">Insert variable</span>
          </Button>
        </PopoverTrigger>
        <PopoverContent side="bottom" align="end" className="w-72 p-0">
          <div className="px-3 py-2 border-b border-border">
            <p className="text-xs font-medium">Available variables</p>
            <p className="text-[11px] text-muted-foreground mt-0.5">
              Substituted at run time with the trigger entity's fields.
            </p>
          </div>
          {variables.length === 0 ? (
            <div className="px-3 py-4 text-sm text-muted-foreground">
              No variables available ÔÇö pick a trigger entity on the Start node first.
            </div>
          ) : (
            <ul className="max-h-72 overflow-y-auto">
              {variables.map((v) => (
                <li key={v.path}>
                  <button
                    type="button"
                    onClick={() => insertToken(v.path)}
                    className="w-full text-left px-3 py-2 hover:bg-muted/40 transition-colors flex flex-col gap-0.5 focus-visible:outline-none focus-visible:bg-muted/40"
                  >
                    <code className="text-xs font-mono text-foreground">{`{{${v.path}}}`}</code>
                    {v.description ? (
                      <span className="text-[11px] text-muted-foreground">{v.description}</span>
                    ) : null}
                  </button>
                </li>
              ))}
            </ul>
          )}
        </PopoverContent>
      </Popover>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Helper ÔÇö derive default variables from a trigger entity kind
// ---------------------------------------------------------------------------

/** Common field paths exposed for each trigger entity kind. */
const DEFAULT_FIELDS_BY_KIND: Record<string, VariableSuggestion[]> = {
  lead: [
    { path: 'trigger.lead.firstName', description: 'Lead given name' },
    { path: 'trigger.lead.lastName', description: 'Lead family name' },
    { path: 'trigger.lead.email', description: 'Lead email' },
    { path: 'trigger.lead.score', description: 'Lead score (0-100)' },
    { path: 'trigger.lead.status', description: 'Lifecycle status' },
  ],
  contact: [
    { path: 'trigger.contact.firstName' },
    { path: 'trigger.contact.lastName' },
    { path: 'trigger.contact.email' },
    { path: 'trigger.contact.phone' },
  ],
  account: [
    { path: 'trigger.account.name' },
    { path: 'trigger.account.industry' },
    { path: 'trigger.account.tier' },
  ],
  deal: [
    { path: 'trigger.deal.name' },
    { path: 'trigger.deal.value', description: 'Monetary value' },
    { path: 'trigger.deal.stage' },
    { path: 'trigger.deal.closeDate' },
  ],
  opportunity: [
    { path: 'trigger.opportunity.name' },
    { path: 'trigger.opportunity.value' },
    { path: 'trigger.opportunity.stage' },
  ],
  case: [
    { path: 'trigger.case.subject' },
    { path: 'trigger.case.priority' },
    { path: 'trigger.case.status' },
  ],
  task: [
    { path: 'trigger.task.title' },
    { path: 'trigger.task.dueDate' },
    { path: 'trigger.task.priority' },
  ],
  user: [{ path: 'trigger.user.name' }, { path: 'trigger.user.email' }],
  team: [{ path: 'trigger.team.name' }],
};

/** Returns the standard variable suggestions for a given entity kind. */
export function variablesForEntityKind(kind: string | undefined): VariableSuggestion[] {
  if (!kind) return [];
  return DEFAULT_FIELDS_BY_KIND[kind] ?? [];
}

'use client';

import * as React from 'react';
import { createPortal } from 'react-dom';
import Link from 'next/link';
import { usePathname, useSearchParams } from 'next/navigation';
import { cn } from '@intelliflow/ui';
import { useSidebar } from './SidebarContext';
import type {
  SidebarConfig,
  SidebarItem,
  SidebarSection,
  SidebarAnnouncement,
} from './sidebar-types';
import { MODULE_COLORS } from './icon-reference';
import { useAuth } from '@/lib/auth';

type ModuleId = keyof typeof MODULE_COLORS;

/** Check whether all item query params are present and matching in the current URL. */
function itemParamsMatchCurrent(
  itemParams: URLSearchParams,
  searchParams: ReturnType<typeof useSearchParams>
): boolean {
  for (const [key, value] of itemParams.entries()) {
    if (searchParams.get(key) !== value) return false;
  }
  return true;
}

interface AppSidebarProps {
  config: SidebarConfig;
  className?: string;
  /** Optional announcement to display at the bottom */
  announcement?: SidebarAnnouncement;
  /** Callback when announcement is dismissed */
  onDismissAnnouncement?: (id: string) => void;
}

interface SidebarSettingsFooterProps {
  config: SidebarConfig;
  isExpanded: boolean;
  hasFooterContent: boolean;
}

function SidebarSettingsFooter({
  config,
  isExpanded,
  hasFooterContent,
}: Readonly<SidebarSettingsFooterProps>) {
  if (config.showSettings === false) return null;
  if (!config.settingsHref && !config.onSettingsClick) return null;

  const itemClass = cn(
    'flex items-center gap-3 px-3 py-2 rounded-lg text-sm transition-colors group',
    'text-muted-foreground hover:text-foreground hover:bg-accent',
    !isExpanded && 'justify-center'
  );

  return (
    <div className={cn('border-t border-border p-2', !hasFooterContent && 'mt-auto')}>
      {config.onSettingsClick ? (
        <button type="button" onClick={config.onSettingsClick} className={cn(itemClass, 'w-full')}>
          <span className="material-symbols-outlined text-xl transition-colors group-hover:text-primary">
            settings
          </span>
          {isExpanded && <span className="font-medium">Module Settings</span>}
        </button>
      ) : (
        <Link href={config.settingsHref!} className={itemClass}>
          <span className="material-symbols-outlined text-xl transition-colors group-hover:text-primary">
            settings
          </span>
          {isExpanded && <span className="font-medium">Module Settings</span>}
        </Link>
      )}
    </div>
  );
}

/**
 * AppSidebar - Collapsible navigation sidebar
 *
 * Features:
 * - Expand on hover, collapse when mouse leaves
 * - Pin/unpin to keep expanded
 * - Context-specific navigation items
 * - Module-specific icon colors (only icons, not backgrounds)
 * - Full dark mode support
 * - Accessible with proper ARIA attributes
 */
export function AppSidebar({
  config,
  className,
  announcement,
  onDismissAnnouncement,
}: Readonly<AppSidebarProps>) {
  const { isExpanded, isPinned, togglePinned, setHovered } = useSidebar();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const { user } = useAuth();

  // Filter out items that require specific roles the current user doesn't have
  const filteredSections = React.useMemo(() => {
    return config.sections
      .map((section) => ({
        ...section,
        items: section.items.filter(
          (item) =>
            !item.roles || item.roles.length === 0 || (user?.role && item.roles.includes(user.role))
        ),
      }))
      .filter((section) => section.items.length > 0);
  }, [config.sections, user?.role]);

  // Get module-specific color theme (only for icon colors)
  const moduleColor = React.useMemo(() => {
    return MODULE_COLORS[config.moduleId as ModuleId] || MODULE_COLORS.dashboard;
  }, [config.moduleId]);

  // Determine active item based on URL
  const isItemActive = React.useCallback(
    (item: Readonly<SidebarItem>): boolean => {
      const itemUrl = new URL(item.href, 'http://localhost');
      const itemPath = itemUrl.pathname;
      const itemParams = itemUrl.searchParams;

      // Check if paths match
      if (pathname !== itemPath && !pathname?.startsWith(itemPath + '/')) {
        return false;
      }

      // For items with query params, check if they all match current URL
      if (itemParams.toString()) {
        return itemParamsMatchCurrent(itemParams, searchParams);
      }

      // For items without params, require exact pathname match
      // AND no query params on the current URL ÔÇö otherwise /email matches /email?folder=sent
      return pathname === itemPath && !searchParams.toString();
    },
    [pathname, searchParams]
  );

  return (
    <nav
      className={cn(
        'fixed left-0 top-16 bottom-0 z-30 flex flex-col bg-card border-r border-border',
        'transition-all duration-300 ease-in-out',
        isExpanded ? 'w-60' : 'w-14',
        'hidden lg:flex',
        className
      )}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      aria-label={`${config.moduleTitle} navigation`}
    >
      {/* Module Header */}
      <div
        className={cn(
          'flex items-center gap-3 px-3 py-4 border-b border-border',
          !isExpanded && 'justify-center'
        )}
      >
        <div
          className={cn(
            'w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0',
            moduleColor.iconBg
          )}
        >
          <span className={cn('material-symbols-outlined text-xl', moduleColor.text)}>
            {config.moduleIcon}
          </span>
        </div>
        {isExpanded ? (
          <div className="flex-1 min-w-0">
            <h2 className="text-sm font-bold text-foreground truncate">{config.moduleTitle}</h2>
          </div>
        ) : null}
        {isExpanded ? (
          <button
            onClick={togglePinned}
            className={cn(
              'p-1 rounded-md transition-colors',
              isPinned
                ? 'text-muted-foreground bg-accent'
                : 'text-muted-foreground hover:text-foreground hover:bg-accent'
            )}
            aria-label={isPinned ? 'Unpin sidebar' : 'Pin sidebar'}
            title={isPinned ? 'Unpin sidebar' : 'Pin sidebar'}
          >
            <span className="material-symbols-outlined text-lg">{'push_pin'}</span>
          </button>
        ) : null}
      </div>

      {/* Before Content (e.g., action buttons) */}
      {config.beforeContent && (
        <div className="px-2 pt-3">
          <config.beforeContent isExpanded={isExpanded} />
        </div>
      )}

      {/* Navigation Sections */}
      <div className="flex-1 overflow-y-auto py-4 px-2">
        <div className="flex flex-col gap-1">
          {filteredSections.map((section, index) => (
            <React.Fragment key={section.id}>
              {/* Section separator (except for first section) */}
              {index > 0 && (
                <div
                  className={cn(
                    'my-3',
                    isExpanded ? 'mx-3 border-t border-border' : 'mx-2 border-t border-border'
                  )}
                />
              )}
              <SidebarSectionComponent
                section={section}
                isExpanded={isExpanded}
                isItemActive={isItemActive}
                moduleColor={moduleColor}
              />
            </React.Fragment>
          ))}
        </div>
        {config.afterContent && (
          <>
            <div
              className={cn(
                'my-3',
                isExpanded ? 'mx-3 border-t border-border' : 'mx-2 border-t border-border'
              )}
            />
            <config.afterContent isExpanded={isExpanded} />
          </>
        )}
      </div>

      {/* Announcement Section - Marketing updates or app announcements */}
      {announcement && isExpanded && (
        <AnnouncementCard announcement={announcement} onDismiss={onDismissAnnouncement} />
      )}

      {/* Footer Content (e.g., storage indicator) */}
      {config.footerContent && (
        <div className="mt-auto border-t border-border px-2 pt-3 pb-1">
          <config.footerContent isExpanded={isExpanded} />
        </div>
      )}

      {/* Settings Footer */}
      <SidebarSettingsFooter
        config={config}
        isExpanded={isExpanded}
        hasFooterContent={!!config.footerContent}
      />
    </nav>
  );
}

interface ModuleColorTheme {
  iconBg: string;
  text: string;
}

interface SidebarSectionComponentProps {
  section: SidebarSection;
  isExpanded: boolean;
  isItemActive: (item: SidebarItem) => boolean;
  moduleColor: ModuleColorTheme;
}

function SidebarSectionComponent({
  section,
  isExpanded,
  isItemActive,
  moduleColor,
}: Readonly<SidebarSectionComponentProps>) {
  return (
    <div>
      {isExpanded && (
        <div className="px-3 mb-2">
          <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">
            {section.title}
          </span>
        </div>
      )}
      <nav className="flex flex-col gap-1" aria-label={section.title}>
        {section.items.map((item) => (
          <SidebarItemComponent
            key={item.id}
            item={item}
            isExpanded={isExpanded}
            isActive={isItemActive(item)}
            moduleColor={moduleColor}
          />
        ))}
