}

interface SidebarItemComponentProps {
  item: SidebarItem;
  isExpanded: boolean;
  isActive: boolean;
  moduleColor: ModuleColorTheme;
}

function SidebarItemComponent({
  item,
  isExpanded,
  isActive,
