/**
 * Automation Rule Builder - PG-173
 *
 * CRUD interface for ticket automation rules. Uses existing routing.* tRPC procedures.
 * REUSES: shadcn Table, Badge, Dialog, Button, Input, Select, Switch, Card
 */

'use client';

import { useState } from 'react';
import { trpc } from '@/lib/trpc';
import {
  Button,
  Badge,
  Switch,
  Input,
  Label,
  Textarea,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@intelliflow/ui';
import { Plus, Pencil, Trash2 } from 'lucide-react';
import { ConfigEmptyState, ConfigCardSkeleton } from './ticket-config-shared';
import { toast } from '@intelliflow/ui';

/**
 * Render a condition object as human-readable chip text.
 */
function formatCondition(condition: Record<string, unknown>): string {
  const field = String(condition.field ?? '').replace(/_/g, ' ');
  const operator = String(condition.operator ?? '');
  const value = String(condition.value ?? '');

  const opMap: Record<string, string> = {
    equals: ':',
    not_equals: 'Ôëá',
    greater_than: '>',
    less_than: '<',
    gte: '>=',
    lte: '<=',
    contains: '~',
    in: 'in',
  };
  const displayOp = opMap[operator] ?? operator;
  const displayField = field.charAt(0).toUpperCase() + field.slice(1);
  return `${displayField} ${displayOp} ${value.toUpperCase()}`;
}

/**
 * Render an action object as human-readable chip text.
 */
function formatAction(action: Record<string, unknown>): string {
  const type = String(action.type ?? '');
  const target = String(action.target ?? '');

  const typeMap: Record<string, string> = {
    assign_to_user: 'Assign to',
    assign_to_skill: 'Assign to',
    assign_to_team: 'Assign to',
    change_status: 'Set status',
    escalate: 'Escalate to',
    notify: 'Notify',
  };
  const displayType = typeMap[type] ?? type;
  return `${displayType}: ${target}`;
}

interface RuleFormData {
  name: string;
  description: string;
  priority: number;
  conditions: Array<{ field: string; operator: string; value: string }>;
  actions: Array<{ type: string; target: string }>;
}

const defaultFormData: RuleFormData = {
  name: '',
  description: '',
  priority: 0,
  conditions: [{ field: 'category', operator: 'equals', value: '' }],
  actions: [{ type: 'assign_to_skill', target: '' }],
};

export function AutomationRuleBuilder() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<RuleFormData>(defaultFormData);

  const utils = trpc.useUtils();
  type AutomationRule = {
    id: string;
    name: string;
    description?: string | null;
    priority: number;
    isActive?: boolean;
    conditions?: unknown;
    actions?: unknown;
  };
  const { data: rulesData, isLoading } = (
    trpc.routing.list as unknown as {
      useQuery: (input: { limit: number }) => {
        data: { items?: AutomationRule[] } | undefined;
        isLoading: boolean;
      };
    }
  ).useQuery({ limit: 100 });

  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- tRPC deep type instantiation workaround
  const createMutation = (trpc.routing.create as any).useMutation({
    onSuccess: () => {
      utils.routing.list.invalidate();
      setDialogOpen(false);
      toast({ title: 'Rule created' });
    },
    onError: (err: { message: string }) =>
      toast({ title: err.message, variant: 'destructive' as const }),
  });
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const updateMutation = (trpc.routing.update as any).useMutation({
    onSuccess: () => {
      utils.routing.list.invalidate();
      setDialogOpen(false);
      setEditingId(null);
      toast({ title: 'Rule updated' });
    },
    onError: (err: { message: string }) =>
      toast({ title: err.message, variant: 'destructive' as const }),
  });
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const deleteMutation = (trpc.routing.delete as any).useMutation({
    onSuccess: () => {
      utils.routing.list.invalidate();
      toast({ title: 'Rule deleted' });
    },
    onError: (err: { message: string }) =>
      toast({ title: err.message, variant: 'destructive' as const }),
  });
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const toggleMutation = (trpc.routing.toggle as any).useMutation({
    onSuccess: () => utils.routing.list.invalidate(),
    onError: (err: { message: string }) =>
      toast({ title: err.message, variant: 'destructive' as const }),
  });

  const rules = rulesData?.items ?? [];

  function openCreate() {
    setEditingId(null);
    setFormData(defaultFormData);
    setDialogOpen(true);
  }

  function openEdit(rule: (typeof rules)[number]) {
    setEditingId(rule.id);
    const conditions = Array.isArray(rule.conditions)
      ? (rule.conditions as Array<Record<string, unknown>>).map((c) => ({
          field: String(c.field ?? 'category'),
          operator: String(c.operator ?? 'equals'),
          value: String(c.value ?? ''),
        }))
      : [{ field: 'category', operator: 'equals', value: '' }];
    const actions = Array.isArray(rule.actions)
      ? (rule.actions as Array<Record<string, unknown>>).map((a) => ({
          type: String(a.type ?? 'assign_to_skill'),
          target: String(a.target ?? ''),
        }))
      : [{ type: 'assign_to_skill', target: '' }];

    setFormData({
      name: rule.name,
      description: rule.description ?? '',
      priority: rule.priority,
      conditions,
      actions,
    });
    setDialogOpen(true);
  }

  function handleSubmit() {
    if (!formData.name.trim()) return;
    const conditions = formData.conditions
      .filter((c) => c.value)
      .map((c) => ({ field: c.field, operator: c.operator, value: c.value }));
    const actions = formData.actions
      .filter((a) => a.target)
      .map((a) => ({ type: a.type, target: a.target }));
    const payload = {
      name: formData.name,
      description: formData.description || undefined,
      priority: formData.priority,
      isActive: true,
      conditions,
      actions,
    };
    if (editingId) {
      updateMutation.mutate({ id: editingId, ...payload });
    } else {
      createMutation.mutate(payload);
    }
  }

  function updateCondition(index: number, field: string, value: string) {
    setFormData((f) => {
      const conditions = [...f.conditions];
      conditions[index] = { ...conditions[index], [field]: value };
      return { ...f, conditions };
    });
  }

  function updateAction(index: number, field: string, value: string) {
    setFormData((f) => {
      const actions = [...f.actions];
      actions[index] = { ...actions[index], [field]: value };
      return { ...f, actions };
    });
  }

  if (isLoading) return <ConfigCardSkeleton />;

  if (!rules.length) {
    return (
      <ConfigEmptyState
        title="No Automation Rules"
        description="Create rules to automatically route, assign, and escalate tickets."
        actionLabel="Create Rule"
        onAction={openCreate}
      />
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-end">
        <Button onClick={openCreate} aria-label="Create new automation rule">
          <Plus className="mr-2 h-4 w-4" />
          Create Rule
        </Button>
      </div>

      <Table aria-label="Automation Rules">
        <TableHeader>
          <TableRow>
            <TableHead>Name</TableHead>
            <TableHead>Priority</TableHead>
            <TableHead>Conditions</TableHead>
            <TableHead>Actions</TableHead>
            <TableHead>Active</TableHead>
            <TableHead>Actions</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {rules.map((rule: AutomationRule) => {
            const conditions = Array.isArray(rule.conditions)
              ? (rule.conditions as Array<Record<string, unknown>>)
              : [];
            const actions = Array.isArray(rule.actions)
              ? (rule.actions as Array<Record<string, unknown>>)
              : [];

            return (
              <TableRow key={rule.id}>
                <TableCell className="font-medium">{rule.name}</TableCell>
                <TableCell>
                  <Badge variant="outline">{rule.priority}</Badge>
                </TableCell>
                <TableCell>
                  <div className="flex flex-wrap gap-1">
                    {conditions.length > 0 ? (
                      conditions.map((c, i) => (
                        <Badge key={i} variant="secondary" className="text-xs">
                          {formatCondition(c)}
                        </Badge>
                      ))
                    ) : (
                      <span className="text-xs text-muted-foreground">No conditions</span>
                    )}
                  </div>
                </TableCell>
                <TableCell>
                  <div className="flex flex-wrap gap-1">
                    {actions.length > 0 ? (
                      actions.map((a, i) => (
                        <Badge key={i} variant="secondary" className="text-xs">
                          {formatAction(a)}
                        </Badge>
                      ))
                    ) : (
                      <span className="text-xs text-muted-foreground">No actions</span>
                    )}
                  </div>
                </TableCell>
                <TableCell>
                  <Switch
                    checked={rule.isActive}
                    onCheckedChange={(checked) =>
                      toggleMutation.mutate({ id: rule.id, isActive: checked })
                    }
                    aria-label={`Toggle ${rule.name} active state`}
                  />
                </TableCell>
                <TableCell>
                  <div className="flex gap-1">
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => openEdit(rule)}
                      aria-label={`Edit ${rule.name}`}
                    >
                      <Pencil className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => deleteMutation.mutate({ id: rule.id })}
                      aria-label={`Delete ${rule.name}`}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            );
          })}
        </TableBody>
      </Table>

      {/* Rule Builder Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{editingId ? 'Edit Rule' : 'Create Automation Rule'}</DialogTitle>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="rule-name">Name</Label>
              <Input
                id="rule-name"
                value={formData.name}
                onChange={(e) => setFormData((f) => ({ ...f, name: e.target.value }))}
                placeholder="e.g. High Priority Billing"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="rule-desc">Description</Label>
              <Textarea
                id="rule-desc"
                value={formData.description}
                onChange={(e) => setFormData((f) => ({ ...f, description: e.target.value }))}
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="rule-priority">Priority</Label>
              <Input
                id="rule-priority"
                type="number"
                min={0}
                value={formData.priority}
                onChange={(e) =>
                  setFormData((f) => ({ ...f, priority: parseInt(e.target.value) || 0 }))
                }
              />
            </div>

            {/* Conditions */}
            <div>
              <h4 className="mb-2 text-sm font-medium">Conditions</h4>
              {formData.conditions.map((condition, idx) => (
                <div key={idx} className="mb-2 grid grid-cols-3 gap-2">
                  <Select
                    value={condition.field}
                    onValueChange={(v) => updateCondition(idx, 'field', v)}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="category">Category</SelectItem>
                      <SelectItem value="priority">Priority</SelectItem>
                      <SelectItem value="slaStatus">SLA Status</SelectItem>
                      <SelectItem value="leadScore">Lead Score</SelectItem>
                      <SelectItem value="leadSource">Lead Source</SelectItem>
                    </SelectContent>
                  </Select>
                  <Select
                    value={condition.operator}
                    onValueChange={(v) => updateCondition(idx, 'operator', v)}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="equals">Equals</SelectItem>
                      <SelectItem value="not_equals">Not Equals</SelectItem>
                      <SelectItem value="greater_than">Greater Than</SelectItem>
                      <SelectItem value="less_than">Less Than</SelectItem>
                      <SelectItem value="gte">Greater or Equal</SelectItem>
                      <SelectItem value="contains">Contains</SelectItem>
                    </SelectContent>
                  </Select>
                  <Input
                    value={condition.value}
                    onChange={(e) => updateCondition(idx, 'value', e.target.value)}
                    placeholder="Value"
                  />
                </div>
              ))}
              <Button
                variant="outline"
                size="sm"
                onClick={() =>
                  setFormData((f) => ({
                    ...f,
                    conditions: [
                      ...f.conditions,
                      { field: 'category', operator: 'equals', value: '' },
                    ],
                  }))
                }
              >
                Add Condition
              </Button>
            </div>

            {/* Actions */}
            <div>
              <h4 className="mb-2 text-sm font-medium">Actions</h4>
              {formData.actions.map((action, idx) => (
                <div key={idx} className="mb-2 grid grid-cols-2 gap-2">
                  <Select value={action.type} onValueChange={(v) => updateAction(idx, 'type', v)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="assign_to_user">Assign to User</SelectItem>
                      <SelectItem value="assign_to_skill">Assign to Skill Group</SelectItem>
                      <SelectItem value="assign_to_team">Assign to Team</SelectItem>
                      <SelectItem value="change_status">Change Status</SelectItem>
                      <SelectItem value="escalate">Escalate</SelectItem>
                    </SelectContent>
                  </Select>
                  <Input
                    value={action.target}
                    onChange={(e) => updateAction(idx, 'target', e.target.value)}
                    placeholder="Target"
                  />
                </div>
              ))}
              <Button
                variant="outline"
                size="sm"
                onClick={() =>
                  setFormData((f) => ({
                    ...f,
                    actions: [...f.actions, { type: 'assign_to_skill', target: '' }],
                  }))
                }
              >
                Add Action
              </Button>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit} disabled={!formData.name.trim()}>
              {editingId ? 'Save Changes' : 'Create Rule'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

/**
 * SLAIndicator ÔÇö Unified SLA display component (PG-137)
 *
 * Combines timer, badge, and progress from lib/tickets/sla-badge.tsx
 * with client-side countdown from server timestamps.
 *
 * @implements AC-4 (SLA badges use library components)
 * @implements AC-5 (SLA timers count down client-side)
 */

import { useState, useEffect, useCallback } from 'react';
import type { TicketStatus, SLAStatus } from '@intelliflow/domain';
import { formatSLATime, getSLAConfig } from '@/lib/tickets/ticket-utils';

type DateStringNull = Date | string | null;
type SizeVariant = 'sm' | 'md' | 'lg';

interface SLAIndicatorProps {
  slaStatus: SLAStatus;
  slaTimeRemaining: number; // minutes
  slaResponseDue?: DateStringNull;
  slaResolutionDue?: DateStringNull;
  firstResponseAt?: DateStringNull;
  resolvedAt?: DateStringNull;
  ticketStatus?: TicketStatus;
  size?: SizeVariant;
  showTimer?: boolean;
  showProgress?: boolean;
}

export function SLAIndicator({
  slaStatus,
  slaTimeRemaining,
  ticketStatus,
  size = 'md',
  showTimer = true,
  showProgress = false,
}: Readonly<SLAIndicatorProps>) {
  const [remaining, setRemaining] = useState(slaTimeRemaining);
  const [currentStatus, setCurrentStatus] = useState<SLAStatus>(slaStatus);

  // Recalculate when props change (e.g., after mutation + invalidation)
  useEffect(() => {
    setRemaining(slaTimeRemaining);
    setCurrentStatus(slaStatus);
  }, [slaTimeRemaining, slaStatus]);

  const updateTimer = useCallback(() => {
    setRemaining((prev) => {
      const newVal = prev - 1;
      // Transition from ON_TRACK to AT_RISK at 30 minutes
      if (newVal <= 30 && newVal > 0 && currentStatus === 'ON_TRACK') {
        setCurrentStatus('AT_RISK');
      }
      // Transition to BREACHED
      if (
        newVal <= 0 &&
        currentStatus !== 'BREACHED' &&
        currentStatus !== 'MET' &&
        currentStatus !== 'PAUSED'
      ) {
        setCurrentStatus('BREACHED');
      }
      return newVal;
    });
  }, [currentStatus]);

  // Client-side countdown: update every 60 seconds
  useEffect(() => {
    // Don't count down for terminal states
    if (currentStatus === 'MET' || currentStatus === 'PAUSED') return;
    // Don't count down for resolved/closed tickets
    if (ticketStatus === 'RESOLVED' || ticketStatus === 'CLOSED') return;

    const interval = setInterval(updateTimer, 60 * 1000);
    return () => clearInterval(interval);
  }, [currentStatus, ticketStatus, updateTimer]);

  // Refresh on tab refocus to prevent drift
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        // Re-sync from props on tab refocus
        setRemaining(slaTimeRemaining);
        setCurrentStatus(slaStatus);
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [slaTimeRemaining, slaStatus]);

  const config = getSLAConfig(currentStatus);
  const isBreachedOrAtRisk = currentStatus === 'BREACHED' || currentStatus === 'AT_RISK';

  const sizeClasses = {
    sm: 'text-xs px-1.5 py-0.5 gap-1',
    md: 'text-sm px-2 py-1 gap-1.5',
    lg: 'text-base px-3 py-1.5 gap-2',
  };

  const iconSizes = {
    sm: 'text-[14px]',
    md: 'text-[16px]',
    lg: 'text-[20px]',
  };

  return (
    <div className="flex flex-col gap-1">
      {/* Timer Badge */}
      {showTimer && (
        <output
          className={`inline-flex items-center font-mono font-bold rounded w-fit ${sizeClasses[size]} ${config.bg} ${config.text} ${
            isBreachedOrAtRisk ? 'animate-pulse' : ''
          }`}
          aria-label={`SLA ${config.label}: ${formatSLATime(remaining)} remaining`}
        >
          <span className={`material-symbols-outlined ${iconSizes[size]}`}>{config.icon}</span>
          {formatSLATime(remaining)}
        </output>
      )}

      {/* Status Badge (no timer) */}
      {!showTimer && (
        <span
          className={`inline-flex items-center rounded text-xs font-bold px-2 py-0.5 w-fit ${config.bg} ${config.text}`}
          role="status"
          aria-label={`SLA status: ${config.label}`}
        >
          {config.label}
        </span>
      )}

      {/* Progress Bar */}
      {showProgress && (
        <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
          <div
            className={`h-full transition-all ${(() => {
              if (currentStatus === 'BREACHED') return 'bg-red-500';
              if (currentStatus === 'AT_RISK') return 'bg-yellow-500';
              if (currentStatus === 'MET') return 'bg-green-500';
              if (currentStatus === 'PAUSED') return 'bg-slate-400';
              return 'bg-emerald-500';
            })()}`}
            style={{
              width: `${Math.max(0, Math.min(100, (remaining / Math.max(remaining, 1)) * 100))}%`,
            }}
          />
        </div>
      )}
    </div>
  );
}

/**
 * SLA Policy Manager - PG-173
 *
 * CRUD interface for SLA policies. Uses tRPC for data fetching and mutations.
 * REUSES: shadcn Table, Badge, Dialog, Button, Input, Switch
 */

'use client';

import { useState } from 'react';
import { trpc } from '@/lib/trpc';
import {
  Button,
  Badge,
  Switch,
  Input,
  Label,
  Textarea,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@intelliflow/ui';
import { Star, Plus, Pencil, Trash2 } from 'lucide-react';
import {
  ConfigEmptyState,
  ConfigCardSkeleton,
  formatMinutesToDisplay,
} from './ticket-config-shared';
import { toast } from '@intelliflow/ui';

interface PolicyFormData {
  name: string;
  description: string;
  criticalResponseMinutes: number;
  highResponseMinutes: number;
  mediumResponseMinutes: number;
  lowResponseMinutes: number;
  criticalResolutionMinutes: number;
  highResolutionMinutes: number;
  mediumResolutionMinutes: number;
  lowResolutionMinutes: number;
  warningThresholdPercent: number;
}

const defaultFormData: PolicyFormData = {
  name: '',
  description: '',
  criticalResponseMinutes: 15,
  highResponseMinutes: 60,
  mediumResponseMinutes: 240,
  lowResponseMinutes: 480,
  criticalResolutionMinutes: 120,
  highResolutionMinutes: 480,
  mediumResolutionMinutes: 1440,
  lowResolutionMinutes: 4320,
  warningThresholdPercent: 25,
};

export function SLAPolicyManager() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<PolicyFormData>(defaultFormData);

  const utils = trpc.useUtils();
  const { data: policies, isLoading } = trpc.ticketConfig.slaPolicy.list.useQuery();

  const createMutation = trpc.ticketConfig.slaPolicy.create.useMutation({
    onSuccess: () => {
      utils.ticketConfig.slaPolicy.list.invalidate();
      setDialogOpen(false);
      toast({ title: 'Policy created' });
    },
    onError: (err) => toast({ title: err.message, variant: 'destructive' }),
  });
  const updateMutation = trpc.ticketConfig.slaPolicy.update.useMutation({
    onSuccess: () => {
      utils.ticketConfig.slaPolicy.list.invalidate();
      setDialogOpen(false);
      setEditingId(null);
      toast({ title: 'Policy updated' });
    },
    onError: (err) => toast({ title: err.message, variant: 'destructive' }),
  });
  const deleteMutation = trpc.ticketConfig.slaPolicy.delete.useMutation({
    onSuccess: () => {
      utils.ticketConfig.slaPolicy.list.invalidate();
      setDeleteId(null);
      toast({ title: 'Policy deactivated' });
    },
    onError: (err) => toast({ title: err.message, variant: 'destructive' }),
  });
  const setDefaultMutation = trpc.ticketConfig.slaPolicy.setDefault.useMutation({
    onSuccess: () => {
      utils.ticketConfig.slaPolicy.list.invalidate();
      toast({ title: 'Default policy updated' });
    },
    onError: (err) => toast({ title: err.message, variant: 'destructive' }),
  });

  function openCreate() {
    setEditingId(null);
    setFormData(defaultFormData);
    setDialogOpen(true);
  }

  function openEdit(policy: NonNullable<typeof policies>[number]) {
    setEditingId(policy.id);
    setFormData({
      name: policy.name,
      description: policy.description ?? '',
      criticalResponseMinutes: policy.criticalResponseMinutes,
      highResponseMinutes: policy.highResponseMinutes,
      mediumResponseMinutes: policy.mediumResponseMinutes,
      lowResponseMinutes: policy.lowResponseMinutes,
      criticalResolutionMinutes: policy.criticalResolutionMinutes,
      highResolutionMinutes: policy.highResolutionMinutes,
      mediumResolutionMinutes: policy.mediumResolutionMinutes,
      lowResolutionMinutes: policy.lowResolutionMinutes,
      warningThresholdPercent: policy.warningThresholdPercent,
    });
    setDialogOpen(true);
  }

  function handleSubmit() {
    if (!formData.name.trim()) return;
    if (editingId) {
      updateMutation.mutate({ id: editingId, ...formData });
    } else {
      createMutation.mutate(formData);
    }
  }

  function handleToggleActive(id: string, currentActive: boolean) {
    updateMutation.mutate({ id, isActive: !currentActive });
  }

  if (isLoading) return <ConfigCardSkeleton />;

  if (!policies?.length) {
    return (
      <ConfigEmptyState
        title="No SLA Policies"
        description="Create your first SLA policy to define response and resolution time targets."
        actionLabel="Create Policy"
        onAction={openCreate}
      />
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-end">
        <Button onClick={openCreate} aria-label="Create new SLA policy">
          <Plus className="mr-2 h-4 w-4" />
          Create Policy
        </Button>
      </div>

      <Table aria-label="SLA Policies">
        <TableHeader>
          <TableRow>
            <TableHead>Name</TableHead>
            <TableHead>Response Times</TableHead>
            <TableHead>Resolution Times</TableHead>
            <TableHead>Warning %</TableHead>
            <TableHead>Default</TableHead>
            <TableHead>Active</TableHead>
            <TableHead>Actions</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {policies.map((policy) => (
            <TableRow key={policy.id}>
              <TableCell className="font-medium">{policy.name}</TableCell>
              <TableCell className="text-sm text-muted-foreground">
                {formatMinutesToDisplay(policy.criticalResponseMinutes)}/
                {formatMinutesToDisplay(policy.highResponseMinutes)}/
                {formatMinutesToDisplay(policy.mediumResponseMinutes)}/
                {formatMinutesToDisplay(policy.lowResponseMinutes)}
              </TableCell>
              <TableCell className="text-sm text-muted-foreground">
                {formatMinutesToDisplay(policy.criticalResolutionMinutes)}/
                {formatMinutesToDisplay(policy.highResolutionMinutes)}/
                {formatMinutesToDisplay(policy.mediumResolutionMinutes)}/
                {formatMinutesToDisplay(policy.lowResolutionMinutes)}
              </TableCell>
              <TableCell>{policy.warningThresholdPercent}%</TableCell>
              <TableCell>
                {policy.isDefault ? (
                  <Badge variant="secondary" aria-label="Default policy">
                    <Star className="mr-1 h-3 w-3" /> Default
                  </Badge>
                ) : (
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setDefaultMutation.mutate({ id: policy.id })}
                    aria-label={`Set ${policy.name} as default`}
                  >
                    Set Default
                  </Button>
                )}
              </TableCell>
              <TableCell>
                <Switch
                  checked={policy.isActive}
                  onCheckedChange={() => handleToggleActive(policy.id, policy.isActive)}
                  aria-label={`Toggle ${policy.name} active state`}
                />
              </TableCell>
              <TableCell>
                <div className="flex gap-1">
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => openEdit(policy)}
                    aria-label={`Edit ${policy.name}`}
                  >
                    <Pencil className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setDeleteId(policy.id)}
                    aria-label={`Delete ${policy.name}`}
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </div>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{editingId ? 'Edit SLA Policy' : 'Create SLA Policy'}</DialogTitle>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="name">Name</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData((f) => ({ ...f, name: e.target.value }))}
                placeholder="e.g. Standard SLA"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                value={formData.description}
                onChange={(e) => setFormData((f) => ({ ...f, description: e.target.value }))}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <h4 className="mb-2 text-sm font-medium">Response Times (minutes)</h4>
                {(['critical', 'high', 'medium', 'low'] as const).map((priority) => (
                  <div key={priority} className="mb-2 flex items-center gap-2">
                    <Label className="w-20 capitalize">{priority}</Label>
                    <Input
                      type="number"
                      min={1}
                      value={formData[`${priority}ResponseMinutes`]}
                      onChange={(e) =>
                        setFormData((f) => ({
                          ...f,
                          [`${priority}ResponseMinutes`]: parseInt(e.target.value) || 1,
                        }))
                      }
                    />
                  </div>
                ))}
              </div>
              <div>
                <h4 className="mb-2 text-sm font-medium">Resolution Times (minutes)</h4>
                {(['critical', 'high', 'medium', 'low'] as const).map((priority) => (
                  <div key={priority} className="mb-2 flex items-center gap-2">
                    <Label className="w-20 capitalize">{priority}</Label>
                    <Input
                      type="number"
                      min={1}
                      value={formData[`${priority}ResolutionMinutes`]}
                      onChange={(e) =>
                        setFormData((f) => ({
                          ...f,
                          [`${priority}ResolutionMinutes`]: parseInt(e.target.value) || 1,
                        }))
                      }
                    />
                  </div>
                ))}
              </div>
            </div>
            <div className="grid gap-2">
              <Label htmlFor="warningThreshold">Warning Threshold (%)</Label>
              <Input
                id="warningThreshold"
                type="number"
                min={1}
                max={100}
                value={formData.warningThresholdPercent}
                onChange={(e) =>
                  setFormData((f) => ({
                    ...f,
                    warningThresholdPercent: parseInt(e.target.value) || 25,
                  }))
                }
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit} disabled={!formData.name.trim()}>
              {editingId ? 'Save Changes' : 'Create Policy'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <AlertDialog open={!!deleteId} onOpenChange={(open) => !open && setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate SLA Policy?</AlertDialogTitle>
            <AlertDialogDescription>
              This will deactivate the policy. Existing tickets using this policy will not be
              affected.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={() => deleteId && deleteMutation.mutate({ id: deleteId })}>
              Deactivate
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

