/**
 * WorkflowEdge ÔÇö custom React Flow edge with a hover-revealed delete affordance.
 *
 * Renders the default smooth-step path PLUS an interactive button at the
 * midpoint that lets the user remove the edge with a single click. Without
 * this, edge removal was only reachable via keyboard (Delete on a
 * selected edge) ÔÇö a hidden affordance the user explicitly flagged.
 */

import { memo } from 'react';
import {
  BaseEdge,
  EdgeLabelRenderer,
  getSmoothStepPath,
  useReactFlow,
  type EdgeProps,
} from '@xyflow/react';
import { X } from 'lucide-react';

function WorkflowEdgeInner(props: EdgeProps) {
  const {
    id,
    sourceX,
    sourceY,
    targetX,
    targetY,
    sourcePosition,
    targetPosition,
    selected,
    style,
    markerEnd,
  } = props;

  const { setEdges } = useReactFlow();

  const [path, labelX, labelY] = getSmoothStepPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const handleDelete = (event: React.MouseEvent | React.PointerEvent) => {
    event.stopPropagation();
    setEdges((eds) => eds.filter((e) => e.id !== id));
  };

  return (
    <>
      <BaseEdge
        id={id}
        path={path}
        markerEnd={markerEnd}
        style={{
          strokeWidth: selected ? 2 : 1.5,
          stroke: selected ? '#3b82f6' : '#94a3b8',
          ...style,
        }}
      />
      <EdgeLabelRenderer>
        {/* The wrapper has `pointer-events-auto` so the inner button is
            clickable; the outer ReactFlow surface uses pointer-events-none
            on edge labels by default. The wrapper is invisible until
            hovered or when the edge is selected, and on touch it's always
            visible (touch:opacity-100). */}
        <div
          className="absolute pointer-events-auto"
          style={{
            transform: `translate(-50%, -50%) translate(${labelX}px, ${labelY}px)`,
          }}
        >
          <button
            type="button"
            onClick={handleDelete}
            onPointerDown={(e) => e.stopPropagation()}
            aria-label="Remove connection"
            className={[
              'flex h-5 w-5 items-center justify-center rounded-full',
              'bg-background border border-border shadow-sm',
              'text-muted-foreground hover:text-rose-600 hover:border-rose-300',
              'transition-opacity',
              selected ? 'opacity-100' : 'opacity-0 hover:opacity-100',
            ].join(' ')}
          >
            <X className="h-3 w-3" aria-hidden="true" />
          </button>
        </div>
      </EdgeLabelRenderer>
    </>
  );
}

export const WorkflowEdge = memo(WorkflowEdgeInner);

/** Edge type key registered with React Flow's `edgeTypes` prop. */
export const WORKFLOW_EDGE_TYPE = 'workflow-edge';

/** Map for the `edgeTypes` prop. */
export const workflowEdgeTypes = {
  [WORKFLOW_EDGE_TYPE]: WorkflowEdge,
};

'use client';

/**
 * WorkflowNodeCard
 *
 * Custom React Flow node renderer. Shows:
 *  - The type accent (colored badge with emoji + UPPERCASE label)
 *  - The user-set display label
 *  - A live summary chip-row reflecting the node's configuration so users
 *    can see at a glance what the node actually does (priority, action
 *    type, recipient count, message snippet, deadline, etc.) without
 *    having to open the config sheet for every node.
 */

import { memo } from 'react';
import { Handle, NodeResizer, Position, type NodeProps } from '@xyflow/react';
import type { WorkflowNodeConfig, WorkflowNodeType as WFNodeType } from '@/lib/workflow-types';

// ---------------------------------------------------------------------------
// Node type visual config
// ---------------------------------------------------------------------------

interface NodeTypeConfig {
  label: string;
  color: string;
  textColor: string;
  emoji: string;
}

const NODE_TYPE_CONFIG: Record<WFNodeType, NodeTypeConfig> = {
  start: {
    label: 'Start',
    color: 'bg-green-100 border-green-400',
    textColor: 'text-green-800',
    emoji: 'ÔûÂ',
  },
  action: {
    label: 'Action',
    color: 'bg-blue-100 border-blue-400',
    textColor: 'text-blue-800',
    emoji: 'ÔÜí',
  },
  decision: {
    label: 'Decision',
    color: 'bg-yellow-100 border-yellow-400',
    textColor: 'text-yellow-800',
    emoji: 'Ôæé',
  },
  human: {
    label: 'Human',
    color: 'bg-purple-100 border-purple-400',
    textColor: 'text-purple-800',
    emoji: '­ƒæñ',
  },
  end: {
    label: 'End',
    color: 'bg-red-100 border-red-400',
    textColor: 'text-red-800',
    emoji: 'Ôûá',
  },
};

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

type WorkflowNodeData = {
  label: string;
  config: WorkflowNodeConfig;
};

const PRIORITY_CHIP_CLASS: Record<string, string> = {
  LOW: 'bg-slate-200 text-slate-700',
  MEDIUM: 'bg-sky-200 text-sky-800',
  HIGH: 'bg-amber-200 text-amber-800',
  URGENT: 'bg-rose-200 text-rose-800',
};

const ACTION_LABEL: Record<string, string> = {
  send_notification: 'Notify',
  notify: 'Notify',
  create_task: 'Create task',
  update_field: 'Update field',
  call_webhook: 'Webhook',
  trigger_workflow: 'Trigger workflow',
  log_event: 'Log',
  log: 'Log',
};

/**
 * Build a list of summary chips from the node's config, ordered from
 * "what kind of action" to "who/where" to "constraints". Returns at most
 * 4 chips so a node card stays compact at typical zoom levels.
 */
function configChips(
  nodeType: WFNodeType,
  cfg: WorkflowNodeConfig
): Array<{ key: string; text: string; className: string }> {
  const chips: Array<{ key: string; text: string; className: string }> = [];

  if (nodeType === 'action' && cfg.actionType) {
    chips.push({
      key: 'actionType',
      text: ACTION_LABEL[cfg.actionType] ?? cfg.actionType,
      className: 'bg-sky-100 text-sky-800',
    });
  }

  if (cfg.priority) {
    chips.push({
      key: 'priority',
      text: cfg.priority.charAt(0) + cfg.priority.slice(1).toLowerCase(),
      className: PRIORITY_CHIP_CLASS[cfg.priority] ?? 'bg-slate-200 text-slate-700',
    });
  }

  // Recipient or assignee summary
  const recipientCount = Array.isArray(cfg.recipients) ? cfg.recipients.length : 0;
  const approverCount = Array.isArray(cfg.approvers) ? cfg.approvers.length : 0;
  if (recipientCount > 0) {
    chips.push({
      key: 'recipients',
      text: `${recipientCount} recipient${recipientCount === 1 ? '' : 's'}`,
      className: 'bg-emerald-100 text-emerald-800',
    });
  }
  if (approverCount > 0) {
    chips.push({
      key: 'approvers',
      text: `${approverCount} approver${approverCount === 1 ? '' : 's'}`,
      className: 'bg-violet-100 text-violet-800',
    });
  }
  if (cfg.assignee?.label) {
    chips.push({
      key: 'assignee',
      text: `ÔåÆ ${cfg.assignee.label}`,
      className: 'bg-emerald-100 text-emerald-800',
    });
  }

  // Linked entity (e.g. create_task ÔåÆ Lead)
  if (cfg.linkedEntity?.label || cfg.linkedEntity?.kind) {
    chips.push({
      key: 'linked',
      text: cfg.linkedEntity.label
        ? `${cfg.linkedEntity.kind}: ${cfg.linkedEntity.label}`
        : `${cfg.linkedEntity.kind}`,
      className: 'bg-indigo-100 text-indigo-800',
    });
  }

  // Trigger / decision specifics
  if (nodeType === 'start' && cfg.triggerType) {
    chips.push({
      key: 'trigger',
      text: cfg.triggerType,
      className: 'bg-emerald-100 text-emerald-800',
    });
  }
  if (nodeType === 'decision') {
    const condCount = Array.isArray(cfg.conditions) ? cfg.conditions.length : 0;
    if (condCount > 0) {
      chips.push({
        key: 'conditions',
        text: `${condCount} condition${condCount === 1 ? '' : 's'}`,
        className: 'bg-amber-100 text-amber-800',
      });
    }
  }

  // Deadline (human / create_task)
  if (typeof cfg.deadlineInHours === 'number' && cfg.deadlineInHours > 0) {
    chips.push({
      key: 'deadline',
      text: `${cfg.deadlineInHours}h deadline`,
      className: 'bg-rose-100 text-rose-800',
    });
  } else if (typeof cfg.dueInHours === 'number' && cfg.dueInHours > 0) {
    chips.push({
      key: 'due',
      text: `due in ${cfg.dueInHours}h`,
      className: 'bg-rose-100 text-rose-800',
    });
  }

  return chips.slice(0, 4);
}

/** Optional one-line preview of free-text fields (message / instructions). */
function configPreview(cfg: WorkflowNodeConfig): string | null {
  if (cfg.message && cfg.message.trim().length > 0) return cfg.message.trim();
  if (cfg.title && cfg.title.trim().length > 0) return cfg.title.trim();
  if (cfg.instructions && cfg.instructions.trim().length > 0) return cfg.instructions.trim();
  return null;
}

function WorkflowNodeCardInner(props: NodeProps) {
  const nodeType = (props.type ?? 'action') as WFNodeType;
  const data = props.data as unknown as WorkflowNodeData;
  const cfg = NODE_TYPE_CONFIG[nodeType] ?? NODE_TYPE_CONFIG.action;
  const chips = configChips(nodeType, data.config ?? {});
  const preview = configPreview(data.config ?? {});
  const isSelected = props.selected ?? false;

  return (
    <div
      className={`relative rounded-lg border-2 shadow-sm min-w-[180px] ${cfg.color}`}
      role="figure"
      aria-label={`${cfg.label} node: ${data.label}`}
      style={{ width: '100%', height: '100%' }}
    >
      {/* NodeResizer ÔÇö only visible when selected; constrains to a sensible
          range so users can compact a busy node or expand to read long
          messages without breaking the layout. */}
      <NodeResizer
        isVisible={isSelected}
        minWidth={160}
        minHeight={80}
        maxWidth={420}
        maxHeight={400}
        lineClassName="border-primary"
        handleClassName="!h-2 !w-2 !bg-primary !border !border-primary"
      />
      {/* Incoming handle (not on start node) */}
      {nodeType !== 'start' && (
        <Handle type="target" position={Position.Top} className="w-3 h-3 !bg-gray-400" />
      )}

      {/* Node header */}
      <div className={`flex items-center gap-1.5 px-3 py-2 ${cfg.textColor}`}>
        <span className="text-sm select-none" aria-hidden="true">
          {cfg.emoji}
        </span>
        <span className="text-xs font-semibold uppercase tracking-wide">{cfg.label}</span>
      </div>

      {/* Node display label */}
      <div className="px-3">
        <p className="text-sm text-gray-700 truncate font-medium">{data.label}</p>
      </div>

      {/* Config summary chips */}
      {chips.length > 0 && (
        <div className="px-3 pt-1.5 flex flex-wrap gap-1">
          {chips.map((chip) => (
            <span
              key={chip.key}
              className={`text-[10px] leading-none font-medium px-1.5 py-0.5 rounded ${chip.className}`}
            >
              {chip.text}
            </span>
          ))}
        </div>
      )}

      {/* Free-text preview (message / title / instructions) */}
      {preview && (
        <p className="px-3 pt-1.5 pb-0 text-[11px] text-gray-600 line-clamp-2 italic">
          ÔÇ£{preview}ÔÇØ
        </p>
      )}

      <div className="pb-2" />

      {/* Outgoing handle (not on end node) */}
      {nodeType !== 'end' && (
        <Handle type="source" position={Position.Bottom} className="w-3 h-3 !bg-gray-400" />
      )}
    </div>
  );
}

export const WorkflowNodeCard = memo(WorkflowNodeCardInner);

/**
 * nodeTypes map ÔÇö pass to ReactFlow `nodeTypes` prop.
 * Using the same component for all types; type-specific styling is driven
 * by the `type` prop which React Flow automatically passes down.
 */
export const workflowNodeTypes = {
  start: WorkflowNodeCard,
  action: WorkflowNodeCard,
  decision: WorkflowNodeCard,
  human: WorkflowNodeCard,
  end: WorkflowNodeCard,
};

'use client';

/**
 * WorkflowToolbar
 *
 * Toolbar rendered inside ReactFlowProvider (Panel component). Provides
 * save, undo/redo, zoom+, zoom-, and fit-view. Uses the design-system
 * Button + Tooltip primitives and lucide icons so it matches the rest
 * of the app and so disabled states explain themselves on hover.
 */

import { Panel, useReactFlow } from '@xyflow/react';
import { Save, Undo2, Redo2, ZoomIn, ZoomOut, Maximize, Loader2 } from 'lucide-react';
import { Button, Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@intelliflow/ui';
import { useIsMobile } from '@/hooks/useIsMobile';

export interface WorkflowToolbarProps {
  onSave: () => void;
  onAutoLayout?: () => void;
  isValid: boolean;
  isSaving: boolean;
  /** First validation error, shown on the Save tooltip when !isValid */
  validationError?: string;
  canUndo: boolean;
  canRedo: boolean;
  onUndo: () => void;
  onRedo: () => void;
}

interface IconActionProps {
  label: string;
  icon: React.ReactNode;
  onClick: () => void;
  disabled?: boolean;
  disabledReason?: string;
}

function IconAction({ label, icon, onClick, disabled, disabledReason }: IconActionProps) {
  const hoverText = disabled && disabledReason ? disabledReason : label;
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        {/* span wrapper keeps the tooltip target clickable even when the
            inner button is disabled (disabled buttons don't fire events) */}
        <span className="inline-flex">
          <Button
            size="sm"
            variant="ghost"
            onClick={onClick}
            disabled={disabled}
            aria-label={label}
            className="h-8 w-8 p-0"
          >
            {icon}
          </Button>
        </span>
      </TooltipTrigger>
      <TooltipContent side="bottom">{hoverText}</TooltipContent>
    </Tooltip>
  );
}

export function WorkflowToolbar({
  onSave,
  isValid,
  isSaving,
  validationError,
  canUndo,
  canRedo,
  onUndo,
  onRedo,
}: WorkflowToolbarProps) {
  const { zoomIn, zoomOut, fitView } = useReactFlow();
  const isMobile = useIsMobile();

  const saveDisabled = !isValid || isSaving;
  const saveTooltip = isSaving
    ? 'SavingÔÇª'
    : !isValid
      ? (validationError ?? 'Connect every node between a Start and an End before saving.')
      : 'Save workflow';

  const pillContent = (
    <TooltipProvider delayDuration={200}>
      <div
        className="flex items-center gap-1 bg-background/95 backdrop-blur-sm border border-border rounded-full px-1.5 py-1 shadow-lg"
        data-testid="workflow-toolbar"
        data-variant={isMobile ? 'mobile' : 'desktop'}
      >
        {/* Save */}
        <Tooltip>
          <TooltipTrigger asChild>
            <span className="inline-flex">
              <Button
                size="sm"
                onClick={onSave}
                disabled={saveDisabled}
                aria-label="Save workflow"
                className="gap-1.5 h-8"
              >
                {isSaving ? (
                  <Loader2 className="h-4 w-4 animate-spin" aria-hidden="true" />
                ) : (
                  <Save className="h-4 w-4" aria-hidden="true" />
                )}
                {isSaving ? 'SavingÔÇª' : 'Save'}
              </Button>
            </span>
          </TooltipTrigger>
          <TooltipContent side="bottom">{saveTooltip}</TooltipContent>
        </Tooltip>

        <div className="w-px h-5 bg-border mx-1" aria-hidden="true" />

        {/* Undo / Redo */}
        <IconAction
          label="Undo"
          icon={<Undo2 className="h-4 w-4" aria-hidden="true" />}
          onClick={onUndo}
          disabled={!canUndo}
          disabledReason="Nothing to undo"
        />
        <IconAction
          label="Redo"
          icon={<Redo2 className="h-4 w-4" aria-hidden="true" />}
          onClick={onRedo}
          disabled={!canRedo}
          disabledReason="Nothing to redo"
        />

        <div className="w-px h-5 bg-border mx-1" aria-hidden="true" />

        {/* Zoom controls */}
        <IconAction
          label="Zoom in"
          icon={<ZoomIn className="h-4 w-4" aria-hidden="true" />}
          onClick={() => void zoomIn()}
        />
        <IconAction
          label="Zoom out"
          icon={<ZoomOut className="h-4 w-4" aria-hidden="true" />}
          onClick={() => void zoomOut()}
        />
        <IconAction
          label="Fit view"
          icon={<Maximize className="h-4 w-4" aria-hidden="true" />}
          onClick={() => void fitView()}
        />
      </div>
    </TooltipProvider>
  );

  if (isMobile) {
    // Floating bottom-center FAB row. Render outside the ReactFlow
    // <Panel> so it escapes the canvas padding and lives above the
    // keyboard/drawer layer on small screens.
    return (
      <div
        className="fixed bottom-4 left-1/2 -translate-x-1/2 z-40 pointer-events-auto"
        data-testid="workflow-toolbar-mobile-wrap"
      >
        {pillContent}
      </div>
    );
  }

  return <Panel position="top-right">{pillContent}</Panel>;
}
